import React, { useState, useEffect, useRef } from 'react';
import { Sparkles, MessageSquare, Send, Bot, RefreshCw, Lightbulb, TrendingDown, AlertCircle } from 'lucide-react';
import { MOCK_EXPENSES } from '../constants';
import { generateExpenseInsights, chatWithAI } from '../services/geminiService';
import { InsightsData } from '../types';

const AiInsights: React.FC = () => {
  const [insights, setInsights] = useState<InsightsData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [chatMessages, setChatMessages] = useState<{role: 'user' | 'ai', text: string}[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetchInsights();
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatMessages, isTyping]);

  const fetchInsights = async () => {
    setIsLoading(true);
    try {
      const data = await generateExpenseInsights(MOCK_EXPENSES);
      setInsights(data);
    } catch (error) {
      console.error('Failed to fetch insights', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setInput('');
    setChatMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const aiResponse = await chatWithAI(userMsg, MOCK_EXPENSES);
      setChatMessages(prev => [...prev, { role: 'ai', text: aiResponse || "Sorry, I couldn't process that." }]);
    } catch (error) {
      setChatMessages(prev => [...prev, { role: 'ai', text: "Error connecting to financial advisor service." }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-5 gap-8 h-[calc(100vh-10rem)]">
      {/* Insights Section */}
      <div className="lg:col-span-3 space-y-6 overflow-y-auto custom-scrollbar pr-2">
        <div className="flex items-center justify-between mb-2">
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <Sparkles className="text-indigo-600" />
            AI Financial Insights
          </h1>
          <button 
            onClick={fetchInsights}
            disabled={isLoading}
            className="p-2 text-slate-500 hover:text-indigo-600 transition-colors disabled:opacity-50"
          >
            <RefreshCw size={20} className={isLoading ? 'animate-spin' : ''} />
          </button>
        </div>

        {isLoading && (
          <div className="p-12 text-center space-y-4 bg-white dark:bg-slate-800 rounded-3xl border border-gray-100 dark:border-slate-700 animate-pulse">
            <div className="w-16 h-16 bg-indigo-50 dark:bg-indigo-900/20 rounded-full mx-auto flex items-center justify-center">
              <Bot className="text-indigo-600 animate-bounce" size={32} />
            </div>
            <p className="text-slate-500 font-medium">Analyzing your spending habits...</p>
          </div>
        )}

        {!isLoading && insights && (
          <>
            <div className="bg-indigo-600 text-white p-8 rounded-3xl shadow-xl shadow-indigo-200 dark:shadow-none space-y-4">
              <h3 className="text-lg font-bold flex items-center gap-2">
                <AlertCircle size={20} />
                Executive Summary
              </h3>
              <p className="text-indigo-50 leading-relaxed italic">
                "{insights.summary}"
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {insights.suggestions.map((s, i) => (
                <div key={i} className="bg-white dark:bg-slate-800 p-6 rounded-2xl border border-gray-100 dark:border-slate-700 hover:shadow-md transition-shadow">
                  <div className="w-10 h-10 bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 rounded-xl flex items-center justify-center mb-4">
                    <TrendingDown size={20} />
                  </div>
                  <p className="text-sm font-semibold leading-snug">{s}</p>
                </div>
              ))}
            </div>

            <div className="bg-amber-50 dark:bg-amber-900/10 border border-amber-200 dark:border-amber-900/30 p-6 rounded-2xl flex gap-4">
              <Lightbulb className="text-amber-500 shrink-0" size={24} />
              <div>
                <h4 className="font-bold text-amber-800 dark:text-amber-400">Pro-Tip</h4>
                <p className="text-sm text-amber-700 dark:text-amber-500/80 mt-1">
                  Users who review their category-wise breakdown weekly reduce unauthorized software subscriptions by 18% on average.
                </p>
              </div>
            </div>
          </>
        )}
      </div>

      {/* AI Chat Section */}
      <div className="lg:col-span-2 flex flex-col bg-white dark:bg-slate-800 rounded-3xl border border-gray-100 dark:border-slate-700 overflow-hidden shadow-sm">
        <div className="p-4 border-b border-gray-100 dark:border-slate-700 bg-gray-50/50 dark:bg-slate-900/50 flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-full flex items-center justify-center text-white">
            <Bot size={24} />
          </div>
          <div>
            <h3 className="font-bold text-sm">Financial Assistant</h3>
            <p className="text-[10px] text-emerald-500 font-bold uppercase tracking-widest flex items-center gap-1">
              <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
              Always Online
            </p>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar" ref={scrollRef}>
          {chatMessages.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-center px-6 opacity-50">
              <MessageSquare size={48} className="mb-4 text-slate-300" />
              <p className="text-sm font-medium">Ask me anything about your expenses.</p>
              <p className="text-xs mt-1 italic">"How much did I spend on Uber this month?"</p>
            </div>
          )}
          {chatMessages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm ${
                msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-gray-100 dark:bg-slate-700 text-slate-800 dark:text-slate-100 rounded-tl-none'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start">
              <div className="bg-gray-100 dark:bg-slate-700 px-4 py-2 rounded-2xl rounded-tl-none flex gap-1 items-center">
                <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></span>
                <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></span>
                <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></span>
              </div>
            </div>
          )}
        </div>

        <div className="p-4 border-t border-gray-100 dark:border-slate-700">
          <div className="relative">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Type your question..."
              className="w-full pl-4 pr-12 py-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-2xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600/20"
            />
            <button 
              onClick={handleSend}
              className="absolute right-2 top-1.5 p-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors"
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AiInsights;

