    }
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  // Authentication Guard
  if (!isAuthenticated) {
    return (
      <AuthPage 
        mode={authMode} 
        setMode={setAuthMode} 
        onLogin={() => setIsAuthenticated(true)} 
      />
    );
  }

  // Selection Screen Guard (Switch between Company or Personal)
  if (!expenseMode) {
    return (
      <SelectionScreen 
        onSelect={(mode) => setExpenseMode(mode)} 
        isDarkMode={isDarkMode}
      />
    );
  }

  const renderView = () => {
    switch (currentView) {
      case AppView.DASHBOARD: return <Dashboard mode={expenseMode} isDarkMode={isDarkMode} onNavigate={setCurrentView} />;
      case AppView.EXPENSES:
      case AppView.EMPLOYEE_EXPENSES:
        return <ExpenseManager mode={expenseMode} />;
      case AppView.BUDGETS:
        return <BudgetTracker />;
      case AppView.SAVINGS_GOALS:
        return <SavingsGoals />;
      case AppView.CATEGORIES:
        return <Categories />;
      case AppView.SUBSCRIPTIONS:
        return <Subscriptions />;
      case AppView.REPORTS: return <Reports />;
      case AppView.APPROVALS: return <Approvals />;
      case AppView.REIMBURSEMENTS: return <Reimbursements />;
      case AppView.AI_INSIGHTS: return <AiInsights />;
      case AppView.SETTINGS: return <Settings user={MOCK_USER} />;
      default: return <Dashboard mode={expenseMode} isDarkMode={isDarkMode} onNavigate={setCurrentView} />;
    }
  };

  return (
    <Layout 
      currentView={currentView} 
      setCurrentView={setCurrentView} 
      user={MOCK_USER}
      expenseMode={expenseMode}
      onLogout={() => {
        setIsAuthenticated(false);
        setExpenseMode(null);
      }}
      onChangeMode={() => setExpenseMode(null)}
      isDarkMode={isDarkMode}
      toggleDarkMode={toggleDarkMode}
    >
      {renderView()}
    </Layout>
  );
};

export default App;

