const INITIAL_CATEGORIES: CategoryItem[] = [
  { name: 'Food & Dining', icon: Utensils, count: 24, spent: 450, budget: 600, color: 'emerald' },
  { name: 'Transportation', icon: Car, count: 12, spent: 280, budget: 300, color: 'blue' },
  { name: 'Health', icon: Heart, count: 4, spent: 120, budget: 200, color: 'rose' },
  { name: 'Shopping', icon: ShoppingBag, count: 8, spent: 850, budget: 500, color: 'indigo' },
