          const isOver = cat.spent > cat.budget;
          const percentage = cat.budget > 0 ? Math.min((cat.spent / cat.budget) * 100, 100) : 0;
          const isMenuActive = activeMenu === cat.name;

          return (
            <div key={i} className="bg-white dark:bg-slate-800 p-8 rounded-[3rem] shadow-sm border border-gray-100 dark:border-slate-700 hover:shadow-xl hover:shadow-emerald-500/5 transition-all group relative">
              <div className="flex items-center justify-between mb-8">
                <div className={`p-5 rounded-2xl ${getColorClasses(cat.color)} group-hover:scale-110 transition-transform`}>
                  <cat.icon size={28} />
