        <div className="z-10 space-y-4 text-center lg:text-left">
          <h2 className="text-3xl sm:text-4xl font-black tracking-tight">Category Insights</h2>
          <p className="text-emerald-50 max-w-xl opacity-90 text-lg font-medium leading-relaxed">
            Your "Shopping" category has seen a 40% increase this month compared to your average. 
            Deep dive into your spending patterns with a detailed analysis.
          </p>
        </div>
        <button 
          onClick={() => onNavigate?.(AppView.REPORTS)}
          className="z-10 px-10 py-5 bg-white text-emerald-600 rounded-[2rem] text-lg font-black shadow-2xl hover:bg-emerald-50 hover:-translate-y-1 transition-all active:scale-95 whitespace-nowrap flex items-center gap-2"
        >
          View Detail Analysis
          <ChevronRight size={20} />
        </button>
      </div>

      {/* Add Category Modal */}
      {showAddModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 sm:p-6 bg-slate-900/60 backdrop-blur-md transition-all">
          <form onSubmit={handleAddCategory} className="bg-white dark:bg-slate-800 w-full max-w-xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8 sm:p-10 border-b border-gray-100 dark:border-slate-700 flex items-center justify-between">
              <div>
                <h2 className="text-2xl font-black tracking-tight">Add New Category</h2>
                <p className="text-xs text-slate-500 font-medium mt-1">Create a new spending bucket.</p>
              </div>
              <button type="button" onClick={() => setShowAddModal(false)} className="p-3 bg-gray-100 dark:bg-slate-700 rounded-2xl text-slate-400 hover:text-slate-600 transition-all">
                <X size={20} />
              </button>
            </div>

            <div className="p-8 sm:p-10 space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Category Name</label>
                <input 
                  required
                  type="text" 
                  placeholder="e.g. Fitness, Hobbies, Gifts" 
                  className="w-full p-4 bg-gray-50 dark:bg-slate-900 border border-gray-100 dark:border-slate-700 rounded-2xl focus:ring-4 focus:ring-emerald-100 outline-none"
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Monthly Budget ($)</label>
                <input 
                  required
                  type="number" 
                  placeholder="0.00" 
                  className="w-full p-4 bg-gray-50 dark:bg-slate-900 border border-gray-100 dark:border-slate-700 rounded-2xl focus:ring-4 focus:ring-emerald-100 outline-none"
