import { GoogleGenAI, Type } from "@google/genai";
import { Expense } from '../types';

// Mock DB Keys
const USERS_KEY = 'ea_mock_users';
const EXPENSES_KEY = 'ea_mock_expenses';
const AUTH_KEY = 'token';
const USER_DATA_KEY = 'user';

// Helper to get local data
const getLocalUsers = () => JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
const getLocalExpenses = () => JSON.parse(localStorage.getItem(EXPENSES_KEY) || '[]');
const getLoggedInUser = () => JSON.parse(localStorage.getItem(USER_DATA_KEY) || 'null');

export const apiService = {
  async post(endpoint: string, data: any) {
    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 800));

    if (endpoint === '/auth/signup') {
      const users = getLocalUsers();
      if (users.find((u: any) => u.email === data.email)) {
        throw new Error('User already exists');
      }
      const newUser = { ...data, id: Math.random().toString(36).substr(2, 9), createdAt: new Date() };
      users.push(newUser);
      localStorage.setItem(USERS_KEY, JSON.stringify(users));
      return { message: 'User created' };
    }

    if (endpoint === '/auth/login') {
      const users = getLocalUsers();
      const user = users.find((u: any) => u.email === data.email && u.password === data.password);
      if (!user) throw new Error('Invalid email or password');

      const token = btoa(JSON.stringify({ id: user.id, email: user.email }));
      return { token, user: { name: user.name, email: user.email, id: user.id } };
    }

    if (endpoint === '/expenses') {
      const currentUser = getLoggedInUser();
      if (!currentUser) throw new Error('Unauthorized');

      const expenses = getLocalExpenses();
      const newExpense = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        userId: currentUser.id,
        amount: parseFloat(data.amount),
        status: 'approved' 
      };
      expenses.push(newExpense);
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(expenses));
      return newExpense;
    }

    throw new Error('Endpoint not found');
  },

  async get(endpoint: string) {
    await new Promise(resolve => setTimeout(resolve, 500));
    const currentUser = getLoggedInUser();

    if (endpoint === '/expenses') {
      if (!currentUser) throw new Error('Unauthorized');
      const expenses = getLocalExpenses();
      return expenses.filter((e: any) => e.userId === currentUser.id).reverse();
    }

    if (endpoint === '/ai/insights') {
      if (!currentUser) throw new Error('Unauthorized');

      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);

      if (expenses.length === 0) {
        return { 
          summary: "Start logging your expenses in ₹ INR to receive personalized AI insights.",
          suggestions: ["Add your first expense", "Set a monthly budget", "Check category trends"]
        };
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const expenseData = expenses.slice(0, 30).map((e: any) => 
          `${e.date}: ₹${e.amount} at ${e.merchant} (${e.category})`
        ).join('\n');

        const response = await ai.models.generateContent({
          model: "gemini-3-flash-preview",
          contents: `You are an expert Indian financial advisor. Analyze these household/personal expenses (All amounts are in Indian Rupees - ₹). Provide a summary and 3-5 cost-cutting suggestions tailored to the Indian market.

          Expenses:
          ${expenseData}`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.STRING },
                suggestions: { 
                  type: Type.ARRAY, 
                  items: { type: Type.STRING }
                }
              },
              required: ["summary", "suggestions"]
            },
            thinkingConfig: { thinkingBudget: 0 }
          }
        });

        return JSON.parse(response.text);
      } catch (error) {
        console.error('Gemini Error:', error);
        return {
          summary: "We're having trouble connecting to the AI brain right now.",
          suggestions: ["Check your internet connection", "Try again in a few minutes"]
        };
      }
    }

    throw new Error('Endpoint not found');
  },

  async delete(endpoint: string) {
    const currentUser = getLoggedInUser();
    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint.startsWith('/expenses/')) {
      const id = endpoint.split('/').pop();
      const expenses = getLocalExpenses();
      const filtered = expenses.filter((e: any) => e.id !== id);
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    throw new Error('Endpoint not found');
  }
};

