      localStorage.setItem(EXPENSES_KEY, JSON.stringify(filtered));
      return { success: true };
    }
    throw new Error('Endpoint not found');
  }
};

import React, { useState, useEffect } from 'react';
import { AppView, AuthView, ExpenseMode, User } from './types';
import Layout from './components/Layout';
import AuthPage from './components/Auth';
import SelectionScreen from './components/SelectionScreen';
import Dashboard from './components/Dashboard';
import ExpenseManager from './components/ExpenseManager';
import BudgetTracker from './components/BudgetTracker';
import Reports from './components/Reports';
import Approvals from './components/Approvals';
import Reimbursements from './components/Reimbursements';
import AiInsights from './components/AiInsights';
import Settings from './components/Settings';
import Categories from './components/Categories';
import Subscriptions from './components/Subscriptions';
import SavingsGoals from './components/SavingsGoals';
import { apiService } from './services/api';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(!!localStorage.getItem('token'));
  const [user, setUser] = useState<User | null>(null);
  const [expenseMode, setExpenseMode] = useState<ExpenseMode | null>(null);
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [authMode, setAuthMode] = useState<AuthView>(AuthView.LOGIN);
  const [isDarkMode, setIsDarkMode] = useState<boolean>(false);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const loadUser = async () => {
      if (isAuthenticated) {
        try {
          const userData = await apiService.get('/user/me');
          setUser(userData);
        } catch (err) {
          localStorage.removeItem('token');
          localStorage.removeItem('user');
          setIsAuthenticated(false);
        }
      }
      setIsLoading(false);
    };
    loadUser();
  }, [isAuthenticated]);

  const handleLogin = (userData: User) => {
    setUser(userData);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setIsAuthenticated(false);
    setUser(null);
    setExpenseMode(null);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-slate-900">
        <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return (
      <AuthPage 
        mode={authMode} 
        setMode={setAuthMode} 
        onLogin={(u) => handleLogin(u as User)} 
      />
    );
  }

  if (!expenseMode) {
    return (
      <SelectionScreen 
        userName={user?.name || ''}
        onSelect={(mode) => setExpenseMode(mode)} 
        isDarkMode={isDarkMode}
      />
    );
  }

  const renderView = () => {
    switch (currentView) {
      case AppView.DASHBOARD: return <Dashboard user={user} mode={expenseMode} isDarkMode={isDarkMode} onNavigate={setCurrentView} />;
      case AppView.EXPENSES:
      case AppView.EMPLOYEE_EXPENSES:
        return <ExpenseManager mode={expenseMode} />;
      case AppView.BUDGETS: return <BudgetTracker />;
      case AppView.SAVINGS_GOALS: return <SavingsGoals />;
      case AppView.CATEGORIES: return <Categories onNavigate={setCurrentView} />;
      case AppView.SUBSCRIPTIONS: return <Subscriptions />;
      case AppView.REPORTS: return <Reports />;
      case AppView.APPROVALS: return <Approvals />;
      case AppView.REIMBURSEMENTS: return <Reimbursements />;
      case AppView.AI_INSIGHTS: return <AiInsights />;
      case AppView.SETTINGS: return user ? <Settings user={user} /> : null;
      default: return <Dashboard user={user} mode={expenseMode} isDarkMode={isDarkMode} onNavigate={setCurrentView} />;
    }
  };

  return (
    <Layout 
      currentView={currentView} 
      setCurrentView={setCurrentView} 
      user={user}
      expenseMode={expenseMode}
      onLogout={handleLogout}
      onChangeMode={() => setExpenseMode(null)}
      isDarkMode={isDarkMode}
      toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
    >
      {renderView()}
    </Layout>
  );
};

export default App;

