import React, { useState } from 'react';
import { AuthView, User as UserType } from '../types';
import { Shield, Mail, Lock, User, ArrowRight, Github, Chrome } from 'lucide-react';
import { apiService } from '../services/api';

interface AuthPageProps {
  mode: AuthView;
  setMode: (mode: AuthView) => void;
  // Fix: onLogin now expects a UserType argument to match the handler in App.tsx
  onLogin: (user: UserType) => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ mode, setMode, onLogin }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      if (mode === AuthView.LOGIN) {
        const data = await apiService.post('/auth/login', { email: formData.email, password: formData.password });
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        // Fix: Call onLogin with the user data returned from the API
        onLogin(data.user);
      } else if (mode === AuthView.SIGNUP) {
        await apiService.post('/auth/signup', formData);
        setMode(AuthView.LOGIN);
        setError('Registration successful! Please login.');
        setLoading(false);
        return;
      }
    } catch (err: any) {
      setError(err.message || 'Authentication failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen grid grid-cols-1 lg:grid-cols-2 bg-white text-slate-900 font-sans">
      <div className="hidden lg:flex flex-col justify-between bg-indigo-600 p-16 text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-white/10 rounded-full translate-x-1/2 -translate-y-1/2 blur-3xl"></div>
        <div className="z-10 flex items-center gap-3">
          <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-indigo-600 font-black text-2xl">EA</div>
          <span className="font-bold text-2xl tracking-tight">Expense Analyzer</span>
        </div>
        <div className="z-10 space-y-8 max-w-lg">
          <h1 className="text-6xl font-black leading-tight">Master your business expenses.</h1>
          <p className="text-xl text-indigo-100 leading-relaxed">The intelligent platform for corporate expense management, automated reporting, and AI-driven financial insights.</p>
        </div>
        <div className="z-10 text-indigo-200 text-sm">&copy; 2024 Expense Analyzer Inc. All rights reserved.</div>
      </div>

      <div className="flex flex-col items-center justify-center p-8 sm:p-12 lg:p-24 bg-gray-50/50">
        <div className="w-full max-w-md space-y-8 animate-in slide-in-from-bottom-4 duration-700">
          <div className="text-center lg:text-left">
            <h2 className="text-3xl font-black">
              {mode === AuthView.LOGIN ? 'Welcome back' : mode === AuthView.SIGNUP ? 'Create account' : 'Reset password'}
            </h2>
            {error && <p className="mt-2 text-rose-500 font-bold bg-rose-50 p-3 rounded-xl border border-rose-100">{error}</p>}
          </div>

          <form onSubmit={handleSubmit} className="space-y-5">
            {mode === AuthView.SIGNUP && (
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase">Full Name</label>
                <div className="relative">
                  <User className="absolute left-4 top-3 text-slate-400" size={20} />
                  <input required type="text" placeholder="John Doe" className="w-full pl-12 pr-4 py-3 bg-white border border-gray-200 rounded-2xl focus:outline-none" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                </div>
              </div>
            )}

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase">Email Address</label>
              <div className="relative">
                <Mail className="absolute left-4 top-3 text-slate-400" size={20} />
                <input required type="email" placeholder="name@company.com" className="w-full pl-12 pr-4 py-3 bg-white border border-gray-200 rounded-2xl focus:outline-none" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
              </div>
            </div>

            {mode !== AuthView.FORGOT_PASSWORD && (
              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <label className="text-xs font-bold text-slate-500 uppercase">Password</label>
                  {mode === AuthView.LOGIN && <button type="button" onClick={() => setMode(AuthView.FORGOT_PASSWORD)} className="text-xs font-bold text-indigo-600">Forgot password?</button>}
                </div>
                <div className="relative">
                  <Lock className="absolute left-4 top-3 text-slate-400" size={20} />
                  <input required type="password" placeholder="••••••••" className="w-full pl-12 pr-4 py-3 bg-white border border-gray-200 rounded-2xl focus:outline-none" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
                </div>
              </div>
            )}

            <button type="submit" disabled={loading} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg flex items-center justify-center gap-3 disabled:opacity-50">
              {loading ? <div className="w-6 h-6 border-4 border-white/20 border-t-white rounded-full animate-spin"></div> : (mode === AuthView.LOGIN ? 'Sign In' : 'Get Started')}
              <ArrowRight size={20} />
            </button>
          </form>

          <p className="text-center text-sm text-slate-500 font-medium">
            {mode === AuthView.LOGIN ? "Don't have an account?" : "Already have an account?"}
            <button onClick={() => setMode(mode === AuthView.LOGIN ? AuthView.SIGNUP : AuthView.LOGIN)} className="ml-1 text-indigo-600 font-black">
              {mode === AuthView.LOGIN ? 'Create Account' : 'Sign In'}
            </button>
          </p>
        </div>
      </div>
    </div>
  );
};

export default AuthPage;

