import React, { useState, useEffect } from 'react';
import { Plus, Filter, Search, Download, Trash2, Edit3, MoreVertical, X, Upload, Receipt, Check, FileText, Grid } from 'lucide-react';
import { apiService } from '../services/api';
import { Expense, ExpenseMode } from '../types';

interface ExpenseManagerProps {
  mode: ExpenseMode;
}

const ExpenseManager: React.FC<ExpenseManagerProps> = ({ mode }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [showFilters, setShowFilters] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [userCategories, setUserCategories] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDeleting, setIsDeleting] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    amount: '',
    merchant: '',
    category: '',
    paymentMethod: 'UPI',
    notes: ''
  });

  useEffect(() => {
    fetchExpenses();
    fetchUserCategories();
  }, []);

  const fetchExpenses = async () => {
    setIsLoading(true);
    try {
      const data = await apiService.get('/expenses');
      setExpenses(data);
    } catch (err) {
      console.error('Failed to fetch expenses', err);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchUserCategories = async () => {
    try {
      const cats = await apiService.get('/categories');
      setUserCategories(cats);
      // Set default category if available
      if (cats.length > 0) {
        setFormData(prev => ({ ...prev, category: cats[0].name }));
      }
    } catch (err) {
      console.error('Failed to fetch categories');
    }
  };

  const handleAddExpense = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.category) {
      alert('Please select a category. If none exist, create one in the Categories tab.');
      return;
    }
    try {
      const newExpense = await apiService.post('/expenses', formData);
      setExpenses(prev => [newExpense, ...prev]);
      setShowAddModal(false);
      setFormData({
        date: new Date().toISOString().split('T')[0],
        amount: '',
        merchant: '',
        category: userCategories.length > 0 ? userCategories[0].name : '',
        paymentMethod: 'UPI',
        notes: ''
      });
    } catch (err) {
      alert('Error saving expense');
    }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm('Are you sure you want to delete this transaction permanently?')) return;

    setIsDeleting(id);
    try {
      await apiService.delete(`/expenses/${id}`);
      setExpenses(prevExpenses => prevExpenses.filter(e => e.id !== id));
    } catch (err) {
      alert('Failed to delete the transaction. Please try again.');
    } finally {
      setIsDeleting(null);
    }
  };

  const isCompany = mode === ExpenseMode.COMPANY;
  const themeBgBtn = isCompany ? 'bg-indigo-600' : 'bg-emerald-600';

  const filteredExpenses = expenses.filter(e => {
    const matchesSearch = e.merchant.toLowerCase().includes(searchTerm.toLowerCase()) || e.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || e.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="space-y-6 sm:space-y-8">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black tracking-tighter">{isCompany ? 'Company Claims' : 'Personal Expenses'}</h1>
          <p className="text-slate-500 text-sm font-medium mt-1">Efficiently track your ₹ INR spending.</p>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setShowAddModal(true)} className={`px-8 py-3 ${themeBgBtn} text-white rounded-2xl text-sm font-black shadow-lg transition-all active:scale-95`}>
            Add Expense
          </button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-800 p-6 rounded-[2.5rem] border border-gray-100 flex flex-col md:flex-row gap-4 items-center shadow-sm">
        <div className="relative flex-1 w-full">
          <Search size={18} className="absolute left-4 top-3.5 text-slate-400" />
          <input type="text" placeholder="Search expenses..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-12 pr-4 py-3.5 bg-gray-50 dark:bg-slate-900 border rounded-2xl outline-none" />
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          <select 
            value={selectedCategory} 
            onChange={e => setSelectedCategory(e.target.value)}
            className="px-4 py-3.5 bg-gray-50 dark:bg-slate-900 border rounded-2xl text-sm font-bold outline-none grow md:grow-0"
          >
            <option>All</option>
            {userCategories.map(c => <option key={c.id}>{c.name}</option>)}
          </select>
          <button onClick={() => setShowFilters(!showFilters)} className={`px-6 py-3.5 bg-gray-50 border rounded-2xl text-sm font-black`}>Filter</button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-800 rounded-[3rem] border border-gray-100 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-gray-50 dark:bg-slate-900">
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Date</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Merchant</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Category</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Amount</th>
                <th className="px-8 py-5"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-slate-700">
              {isLoading ? (
                <tr><td colSpan={5} className="px-8 py-20 text-center font-bold">Loading transactions...</td></tr>
              ) : filteredExpenses.length === 0 ? (
                <tr><td colSpan={5} className="px-8 py-20 text-center text-slate-400 italic">No expenses found matching your criteria.</td></tr>
              ) : filteredExpenses.map(expense => (
                <tr key={expense.id} className={`hover:bg-gray-50 dark:hover:bg-slate-700/50 transition-colors group ${isDeleting === expense.id ? 'opacity-30' : ''}`}>
                  <td className="px-8 py-6 text-sm font-bold text-slate-400">{new Date(expense.date).toLocaleDateString()}</td>
                  <td className="px-8 py-6 font-black">{expense.merchant}</td>
                  <td className="px-8 py-6"><span className="px-3 py-1 bg-gray-100 dark:bg-slate-700 rounded-lg text-[10px] font-black uppercase tracking-widest">{expense.category}</span></td>
                  <td className="px-8 py-6 text-sm font-black">₹{expense.amount.toLocaleString('en-IN')}</td>
                  <td className="px-8 py-6 text-right">
                    <button 
                      onClick={() => handleDelete(expense.id)} 
                      disabled={isDeleting === expense.id}
                      className="p-2 text-slate-400 hover:text-rose-600 disabled:opacity-50 transition-colors"
                    >
                      <Trash2 size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md transition-all">
          <form onSubmit={handleAddExpense} className="bg-white dark:bg-slate-800 w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-6 sm:p-10 border-b dark:border-slate-700 flex items-center justify-between">
              <h2 className="text-2xl font-black">Add Expense (₹ INR)</h2>
              <button type="button" onClick={() => setShowAddModal(false)}><X size={20} /></button>
            </div>
            <div className="p-10 space-y-6">
              {userCategories.length === 0 ? (
                <div className="p-8 bg-amber-50 dark:bg-amber-900/20 border-2 border-dashed border-amber-200 dark:border-amber-800 rounded-2xl text-center space-y-4">
                  <Grid size={32} className="mx-auto text-amber-500" />
                  <p className="text-amber-800 dark:text-amber-400 font-bold">No Categories Found</p>
                  <p className="text-xs text-amber-700 dark:text-amber-500">You must create at least one category in the "Categories" section before you can add an expense.</p>
                </div>
              ) : (
                <>
                  <div className="grid grid-cols-2 gap-6">
                    <input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="p-4 bg-gray-50 dark:bg-slate-900 rounded-2xl border dark:border-slate-700 outline-none" />
                    <input required type="number" placeholder="Amount (₹)" value={formData.amount} onChange={e => setFormData({...formData, amount: e.target.value})} className="p-4 bg-gray-50 dark:bg-slate-900 rounded-2xl border dark:border-slate-700 outline-none" />
                  </div>
                  <input required type="text" placeholder="Merchant" value={formData.merchant} onChange={e => setFormData({...formData, merchant: e.target.value})} className="w-full p-4 bg-gray-50 dark:bg-slate-900 rounded-2xl border dark:border-slate-700 outline-none" />

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Select Category</label>
                    <select required value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} className="w-full p-4 bg-gray-50 dark:bg-slate-900 rounded-2xl border dark:border-slate-700 outline-none">
                      {userCategories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                    </select>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Payment Method</label>
                    <select value={formData.paymentMethod} onChange={e => setFormData({...formData, paymentMethod: e.target.value})} className="w-full p-4 bg-gray-50 dark:bg-slate-900 rounded-2xl border dark:border-slate-700 outline-none">
                      <option>UPI</option>
                      <option>Credit Card</option>
                      <option>Cash</option>
                      <option>Net Banking</option>
                    </select>
                  </div>
                </>
              )}
            </div>
            <div className="p-10 bg-gray-50 dark:bg-slate-900/50 flex justify-end gap-3">
              <button type="button" onClick={() => setShowAddModal(false)} className="px-8 py-4 font-black">Cancel</button>
              {userCategories.length > 0 && (
                <button type="submit" className={`px-10 py-4 ${themeBgBtn} text-white rounded-2xl font-black shadow-xl`}>Save Expense</button>
              )}
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

