                    <select value={formData.paymentMethod} onChange={e => setFormData({...formData, paymentMethod: e.target.value})} className="w-full p-4 bg-gray-50 dark:bg-slate-900 rounded-2xl border dark:border-slate-700 outline-none">
                      <option value="UPI">UPI</option>
                      <option value="Credit Card">Credit Card</option>
                      <option value="Cash">Cash</option>
                      <option value="Net Banking">Net Banking</option>
                    </select>
                  </div>
                </>
              )}
            </div>
            <div className="p-10 bg-gray-50 dark:bg-slate-900/50 flex justify-end gap-3">
              <button type="button" onClick={() => setShowAddModal(false)} className="px-8 py-4 font-black hover:bg-gray-100 rounded-xl transition-colors">Cancel</button>
              {userCategories.length > 0 && (
                <button type="submit" className={`px-10 py-4 ${themeBgBtn} text-white rounded-2xl font-black shadow-xl hover:brightness-110 active:scale-95 transition-all`}>Save Expense</button>
              )}
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

