    setIsLoading(true);
    try {
      // In this app, Budgets are essentially Categories with limits
      const categories = await apiService.get('/categories');
      const budgetData = categories.map((cat: any) => ({
        id: cat.id,
        category: cat.name,
        limit: cat.budget || 0,
        spent: cat.spent || 0,
        icon: 'Target'
      }));
      setBudgets(budgetData);
    } catch (err) {
      console.error('Failed to fetch budgets');
    } finally {
      setIsLoading(false);
    }
  };

  const handleCreateBudget = async (e: React.FormEvent) => {
    e.preventDefault();
    // Redirecting to category creation logic since budgets are tied to categories
    try {
      await apiService.post('/categories', {
        name: newBudget.category,
        budget: newBudget.limit,
        color: 'indigo',
        iconName: 'Grid'
      });
      fetchBudgets();
      setShowCreateModal(false);
      setNewBudget({ category: '', limit: 0, icon: 'Target' });
