    e.preventDefault();
    // Implementation for adjusting existing category limits would go here
    // For now, updating local state for UI feedback
    if (!showAdjustModal) return;
    setBudgets(budgets.map(b => 
      b.category === showAdjustModal.category 
      ? { ...b, limit: showAdjustModal.limit } 
      : b
    ));
    setShowAdjustModal(null);
  };

  const handleDeleteBudget = (category: string) => {
    if (confirm(`Are you sure you want to delete the ${category} budget tracking?`)) {
      setBudgets(budgets.filter(b => b.category !== category));
