import jwt from 'jsonwebtoken';
import User from '../models/User';
import OTP from '../models/OTP';

const JWT_SECRET = process.env.JWT_SECRET || 'expense-analyzer-secret-key-2025';

// Simplified hashing helper for the demo (ideally use bcrypt)
const hashValue = (val: string) => val; 

export const register = async (req: any, res: any) => {
  try {
    const { name, email, password } = req.body;

    let user = await User.findOne({ email });
    if (user) return res.status(400).json({ message: 'User already exists' });

    user = new User({ name, email, password, isVerified: false });
    await user.save();

    const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
    const expiresAt = new Date(Date.now() + 5 * 60 * 1000); // 5 minutes

    const otpEntry = new OTP({ email, otp: hashValue(otpCode), expiresAt });
    await otpEntry.save();

    // Logic for sending email would go here using Nodemailer
    console.log(`[AUTH] OTP for ${email}: ${otpCode}`);

    res.json({ message: 'User registered. Please verify your email.', email });
  } catch (err) {
    res.status(500).json({ message: 'Registration failed' });
  }
};

export const login = async (req: any, res: any) => {
  try {
    const { email, password } = req.body;
    const user = await User.findOne({ email });

    if (!user || user.password !== password) {
      return res.status(401).json({ message: 'Invalid credentials' });
    }

    // Always trigger OTP for secure login in this fintech application
    const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
    const expiresAt = new Date(Date.now() + 5 * 60 * 1000);

    await OTP.deleteMany({ email }); // Clear old ones
    const otpEntry = new OTP({ email, otp: hashValue(otpCode), expiresAt });
    await otpEntry.save();

    console.log(`[AUTH] Login OTP for ${email}: ${otpCode}`);

    res.json({ requiresVerification: true, email });
  } catch (err) {
    res.status(500).json({ message: 'Login failed' });
  }
};

export const verifyOtp = async (req: any, res: any) => {
  try {
    const { email, otp } = req.body;
    const otpRecord = await OTP.findOne({ email }).sort({ createdAt: -1 });

    if (!otpRecord) return res.status(400).json({ message: 'OTP not found' });
    if (otpRecord.expiresAt < new Date()) return res.status(400).json({ message: 'OTP expired' });
    if (otpRecord.otp !== hashValue(otp)) {
      otpRecord.attempts += 1;
      await otpRecord.save();
      if (otpRecord.attempts >= 3) {
        await OTP.deleteMany({ email });
        return res.status(400).json({ message: 'Too many attempts. Please request a new code.' });
      }
      return res.status(400).json({ message: 'Invalid OTP' });
    }

    const user = await User.findOne({ email });
    if (!user) return res.status(404).json({ message: 'User not found' });

    user.isVerified = true;
    await user.save();

    const token = jwt.sign({ id: user._id, email: user.email }, JWT_SECRET, { expiresIn: '7d' });

    await OTP.deleteMany({ email });

    res.json({
      token,
      user: {
        id: user._id,
        name: user.name,
        email: user.email,
        role: 'User',
        isVerified: true
      }
    });
  } catch (err) {
    res.status(500).json({ message: 'Verification failed' });
  }
};

export const resendOtp = async (req: any, res: any) => {
  try {
    const { email } = req.body;
    const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
    const expiresAt = new Date(Date.now() + 5 * 60 * 1000);

    await OTP.deleteMany({ email });
    const otpEntry = new OTP({ email, otp: hashValue(otpCode), expiresAt });
    await otpEntry.save();

    console.log(`[AUTH] Resent OTP for ${email}: ${otpCode}`);
    res.json({ message: 'OTP resent' });
  } catch (err) {
    res.status(500).json({ message: 'Failed to resend OTP' });
  }
};

