import { GoogleGenAI, Type } from "@google/genai";
import { User } from '../types';

const USERS_KEY = 'ea_mock_users';
const EXPENSES_KEY = 'ea_mock_expenses';
const CATEGORIES_KEY = 'ea_mock_categories';
const OTPS_KEY = 'ea_mock_otps';
const USER_DATA_KEY = 'user';

const getLocalUsers = () => JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
const getLocalExpenses = () => JSON.parse(localStorage.getItem(EXPENSES_KEY) || '[]');
const getLocalCategories = () => JSON.parse(localStorage.getItem(CATEGORIES_KEY) || '[]');
const getLocalOTPs = () => JSON.parse(localStorage.getItem(OTPS_KEY) || '[]');
const getLoggedInUser = () => JSON.parse(localStorage.getItem(USER_DATA_KEY) || 'null');

export const apiService = {
  async post(endpoint: string, data: any) {
    await new Promise(resolve => setTimeout(resolve, 800));
    const currentUser = getLoggedInUser();

    if (endpoint === '/auth/signup') {
      const users = getLocalUsers();
      if (users.find((u: any) => u.email === data.email)) {
        throw new Error('An account with this email already exists.');
      }
      const newUser = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        createdAt: new Date(),
        role: 'Personal User',
        isVerified: false
      };
      users.push(newUser);
      localStorage.setItem(USERS_KEY, JSON.stringify(users));

      const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
      const otps = getLocalOTPs();
      otps.push({ email: data.email, otp: otpCode, expires: Date.now() + 300000 });
      localStorage.setItem(OTPS_KEY, JSON.stringify(otps));

      console.log(`%c[AUTH SERVICE] OTP for ${data.email}: ${otpCode}`, "color: #4f46e5; font-weight: bold; font-size: 14px;");
      alert(`SIMULATION: Verification code sent to ${data.email}. In development mode, please check your browser console (F12) to see the code.`);

      return { message: 'OTP sent to your email', email: data.email };
    }

    if (endpoint === '/auth/login') {
      const users = getLocalUsers();
      const user = users.find((u: any) => u.email === data.email && u.password === data.password);
      if (!user) throw new Error('Invalid email or password credentials.');

      const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
      const otps = getLocalOTPs();
      otps.push({ email: data.email, otp: otpCode, expires: Date.now() + 300000 });
      localStorage.setItem(OTPS_KEY, JSON.stringify(otps));

      console.log(`%c[AUTH SERVICE] Login OTP for ${data.email}: ${otpCode}`, "color: #4f46e5; font-weight: bold; font-size: 14px;");

      return { requiresVerification: true, email: data.email };
    }

    if (endpoint === '/auth/verify-otp') {
      const otps = getLocalOTPs();
      const record = otps.find((o: any) => o.email === data.email && o.otp === data.otp);

      if (!record) throw new Error('Invalid code. Please check your email or console.');
      if (Date.now() > record.expires) throw new Error('Verification code has expired.');

      const users = getLocalUsers();
      const userIdx = users.findIndex((u: any) => u.email === data.email);
      if (userIdx !== -1) {
        users[userIdx].isVerified = true;
        localStorage.setItem(USERS_KEY, JSON.stringify(users));

        const token = btoa(JSON.stringify({ id: users[userIdx].id, email: users[userIdx].email }));
        const userPublic = { 
          name: users[userIdx].name, 
          email: users[userIdx].email, 
          id: users[userIdx].id, 
          role: users[userIdx].role,
          isVerified: true
        };
        localStorage.setItem(USER_DATA_KEY, JSON.stringify(userPublic));

        const remainingOtps = otps.filter((o: any) => o.email !== data.email);
        localStorage.setItem(OTPS_KEY, JSON.stringify(remainingOtps));

        return { token, user: userPublic };
      }
      throw new Error('User not found.');
    }

    if (endpoint === '/auth/resend-otp') {
      const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
      const otps = getLocalOTPs().filter((o: any) => o.email !== data.email);
      otps.push({ email: data.email, otp: otpCode, expires: Date.now() + 300000 });
      localStorage.setItem(OTPS_KEY, JSON.stringify(otps));
      console.log(`%c[AUTH SERVICE] Resent OTP for ${data.email}: ${otpCode}`, "color: #4f46e5; font-weight: bold; font-size: 14px;");
      return { message: 'New code sent' };
    }

    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      const newExpense = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        userId: currentUser.id,
        amount: parseFloat(data.amount),
        status: 'approved' 
      };
      expenses.push(newExpense);
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(expenses));
      return newExpense;
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const newCategory = {
        ...data,
        userId: currentUser.id,
        id: Math.random().toString(36).substr(2, 9),
      };
      categories.push(newCategory);
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(categories));
      return newCategory;
    }

    throw new Error('Endpoint not found');
  },

  async get(endpoint: string) {
    await new Promise(resolve => setTimeout(resolve, 400));
    const currentUser = getLoggedInUser();

    if (endpoint === '/user/me') {
      if (!currentUser) throw new Error('Unauthorized');
      return currentUser;
    }

    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      return expenses.filter((e: any) => e.userId === currentUser.id).reverse();
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);

      const userCategories = categories.filter((c: any) => c.userId === currentUser.id);

      return userCategories.map((cat: any) => {
        const catExpenses = expenses.filter((e: any) => e.category === cat.name);
        const totalSpent = catExpenses.reduce((sum: number, e: any) => sum + e.amount, 0);
        return {
          ...cat,
          spent: totalSpent,
          count: catExpenses.length
        };
      });
    }

    if (endpoint === '/ai/insights') {
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);

      if (expenses.length === 0) {
        return { 
          summary: `Hi ${currentUser.name}, welcome to Expense Analyzer! Start adding your expenses to unlock personalized AI financial insights.`,
          suggestions: ["Add your first expense", "Track your daily commute costs", "Set a grocery budget"]
        };
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const expenseData = expenses.slice(0, 30).map((e: any) => 
          `${e.date}: ₹${e.amount} at ${e.merchant} (${e.category})`
        ).join('\n');

        const response = await ai.models.generateContent({
          model: "gemini-3-flash-preview",
          contents: `User: ${currentUser.name}. Expenses: ${expenseData}. Analyze these expenses in INR. Provide a 1-sentence summary and 3 tips.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.STRING },
                suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["summary", "suggestions"]
            }
          }
        });

        return JSON.parse(response.text || '{}');
      } catch (error) {
        return { summary: "AI insights temporarily unavailable.", suggestions: [] };
      }
    }
    throw new Error('Endpoint not found');
  },

  async delete(endpoint: string) {
    await new Promise(resolve => setTimeout(resolve, 400));

    const currentUser = getLoggedInUser();
    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint.includes('/expenses/')) {
      const id = endpoint.split('/expenses/')[1].split('/')[0];
      const expenses = getLocalExpenses();

      const filtered = expenses.filter((e: any) => {
        const isTarget = String(e.id) === String(id);
        const belongsToUser = String(e.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(EXPENSES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    if (endpoint.includes('/categories/')) {
      const id = endpoint.split('/categories/')[1].split('/')[0];
      const categories = getLocalCategories();

      const filtered = categories.filter((c: any) => {
        const isTarget = String(c.id) === String(id);
        const belongsToUser = String(c.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    throw new Error(`Endpoint not supported: ${endpoint}`);
  }
};

import nodemailer from 'nodemailer';

/**
 * PRODUCTION-READY SMTP CONFIGURATION
 * 
 * For Gmail:
 * 1. Go to your Google Account -> Security.
 * 2. Enable 2-Step Verification.
 * 3. Search for "App Passwords".
 * 4. Generate a password for "Mail" and "Other (Custom Name: Expense Analyzer)".
 * 5. Use that 16-character password in your .env as EMAIL_PASS.
 */

const transporter = nodemailer.createTransport({
  host: process.env.EMAIL_HOST || 'smtp.gmail.com',
  port: parseInt(process.env.EMAIL_PORT || '465'),
  secure: (process.env.EMAIL_PORT === '465'), // true for 465, false for 587/25
  pool: true, // Use a pool for multiple sends
  maxConnections: 5,
  maxMessages: 100,
  auth: {
    user: process.env.EMAIL_USER, 
    pass: process.env.EMAIL_PASS  
  },
  tls: {
    // Do not fail on invalid certificates (useful for some dev environments)
    rejectUnauthorized: false 
  }
});

/**
 * Sends a secure OTP email with professional branding.
 * @param to Recipient email address
 * @param otp The 6-digit OTP code
 */
export const sendOtpEmail = async (to: string, otp: string): Promise<{ success: boolean; error?: string }> => {
  if (!process.env.EMAIL_USER || !process.env.EMAIL_PASS) {
    console.error('❌ SMTP Credentials missing in environment variables.');
    return { success: false, error: 'Email service configuration missing.' };
  }

  const mailOptions = {
    from: `"Expense Analyzer Security" <${process.env.EMAIL_USER}>`,
    to: to,
    subject: `${otp} is your Expense Analyzer verification code`,
    priority: 'high' as const,
    html: `
      <div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; color: #1e293b; background-color: #ffffff;">
        <div style="padding: 40px 20px; text-align: center; background: linear-gradient(135deg, #4f46e5 0%, #7c3aed 100%); border-radius: 24px 24px 0 0;">
          <h1 style="color: #ffffff; margin: 0; font-size: 28px; font-weight: 800; letter-spacing: -0.025em;">Expense Analyzer</h1>
          <p style="color: #e0e7ff; margin-top: 8px; font-size: 14px; text-transform: uppercase; font-weight: 700; letter-spacing: 0.1em;">Security Verification</p>
        </div>

        <div style="padding: 40px; border: 1px solid #e2e8f0; border-top: none; border-radius: 0 0 24px 24px; text-align: center;">
          <p style="font-size: 16px; color: #64748b; margin-bottom: 32px; line-height: 1.5;">
            Hello,<br>
            Please use the following code to verify your account. This code will expire in <strong>5 minutes</strong>.
          </p>

          <div style="background-color: #f8fafc; border: 2px dashed #cbd5e1; border-radius: 16px; padding: 24px; display: inline-block; margin-bottom: 32px;">
            <span style="font-size: 48px; font-weight: 900; letter-spacing: 8px; color: #4f46e5; font-family: monospace;">${otp}</span>
          </div>

          <div style="background-color: #fff7ed; border: 1px solid #ffedd5; border-radius: 12px; padding: 16px; margin-bottom: 32px; text-align: left;">
            <p style="font-size: 12px; color: #9a3412; margin: 0; line-height: 1.4;">
              <strong>Security Tip:</strong> Never share this code with anyone. Our support team will never ask for your verification code over the phone or email.
            </p>
          </div>

          <p style="font-size: 12px; color: #94a3b8; line-height: 1.6; border-top: 1px solid #f1f5f9; pt: 24px; margin-top: 24px;">
            If you didn't request this code, you can safely ignore this email. Someone may have entered your email address by mistake.
          </p>
        </div>

        <div style="text-align: center; margin-top: 32px; font-size: 11px; color: #cbd5e1; text-transform: uppercase; letter-spacing: 1px;">
          Expense Analyzer Pro &bull; Enterprise Financial Intelligence
        </div>
      </div>
    `
  };

  try {
    // Verify connection configuration
    await transporter.verify();

    // Send email
    const info = await transporter.sendMail(mailOptions);
    console.log(`✅ Email sent successfully to ${to}. MessageId: ${info.messageId}`);
    return { success: true };
  } catch (error: any) {
    console.error('❌ SMTP Error Details:', error);

    let userFriendlyError = 'Failed to deliver email.';
    if (error.code === 'EAUTH') userFriendlyError = 'Authentication failed. Please check SMTP credentials.';
    if (error.code === 'ESOCKET') userFriendlyError = 'Network error. Could not connect to email server.';

    return { success: false, error: userFriendlyError };
  }
};

