  const [successMsg, setSuccessMsg] = useState('');
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [timer, setTimer] = useState(300); // 5 minutes
  const otpRefs = useRef<(HTMLInputElement | null)[]>([]);

  useEffect(() => {
    let interval: any;
    if (mode === AuthView.VERIFY_OTP && timer > 0) {
      interval = setInterval(() => {
        setTimer(prev => prev - 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [mode, timer]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccessMsg('');

    try {
      if (mode === AuthView.LOGIN) {
        const data = await apiService.post('/auth/login', { email: formData.email, password: formData.password });
        if (data.requiresVerification) {
          setMode(AuthView.VERIFY_OTP);
          setTimer(300);
        } else {
          localStorage.setItem('token', data.token);
          localStorage.setItem('user', JSON.stringify(data.user));
          onLogin(data.user);
        }
      } else if (mode === AuthView.SIGNUP) {
        const data = await apiService.post('/auth/signup', formData);
        setMode(AuthView.VERIFY_OTP);
        setTimer(300);
        if (data.emailError) {
          setError('Account created, but we had trouble sending the code: ' + data.emailError);
        }
      } else if (mode === AuthView.VERIFY_OTP) {
        const otpCode = otp.join('');
        if (otpCode.length < 6) throw new Error('Please enter the full 6-digit code.');

        const data = await apiService.post('/auth/verify-otp', { email: formData.email, otp: otpCode });
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        onLogin(data.user);
      }
    } catch (err: any) {
      setError(err.message || 'Authentication failed');
    } finally {
      setLoading(false);
    }
  };

  const handleResendOtp = async () => {
    setLoading(true);
    setError('');
    setSuccessMsg('');
    try {
      await apiService.post('/auth/resend-otp', { email: formData.email });
      setTimer(300);
      setOtp(['', '', '', '', '', '']);
      setSuccessMsg('A new verification code has been sent!');
    } catch (err: any) {
      setError(err.message || 'Resend failed');
    } finally {
      setLoading(false);
    }
  };

  const handleOtpChange = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newOtp = [...otp];
    newOtp[index] = value.slice(-1);
    setOtp(newOtp);

    // Auto focus next
    if (value && index < 5) {
      otpRefs.current[index + 1]?.focus();
    }
  };

  const handleOtpKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      otpRefs.current[index - 1]?.focus();
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  const renderOtpScreen = () => (
    <div className="w-full max-w-md space-y-8 animate-in slide-in-from-bottom-4 duration-700">
      <div className="text-center lg:text-left">
        <button onClick={() => setMode(AuthView.LOGIN)} className="flex items-center gap-2 text-sm font-bold text-slate-500 hover:text-indigo-600 transition-colors mb-4">
          <ChevronLeft size={16} /> Back to Login
        </button>
        <h2 className="text-3xl font-black">Verify your identity</h2>
        <p className="mt-2 text-slate-500 font-medium">We've sent a 6-digit verification code to <br/><span className="text-indigo-600 font-bold">{formData.email}</span></p>

        {error && (
          <div className="mt-4 p-4 rounded-2xl bg-rose-50 border border-rose-100 text-rose-600 text-sm font-bold flex items-start gap-3">
            <AlertCircle className="shrink-0 mt-0.5" size={18} />
            <span>{error}</span>
          </div>
        )}

        {successMsg && (
          <div className="mt-4 p-4 rounded-2xl bg-emerald-50 border border-emerald-100 text-emerald-600 text-sm font-bold flex items-start gap-3">
            <ShieldCheck className="shrink-0 mt-0.5" size={18} />
            <span>{successMsg}</span>
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">
        <div className="flex justify-between gap-2">
          {otp.map((digit, i) => (
            <input
              key={i}
              ref={el => { otpRefs.current[i] = el; }}
              type="text"
              inputMode="numeric"
              maxLength={1}
              value={digit}
              onChange={e => handleOtpChange(i, e.target.value)}
              onKeyDown={e => handleOtpKeyDown(i, e)}
              className="w-12 h-16 sm:w-14 sm:h-20 text-center text-3xl font-black bg-white dark:bg-slate-800 border-2 border-gray-100 dark:border-slate-700 rounded-2xl focus:border-indigo-600 focus:ring-4 focus:ring-indigo-100 outline-none transition-all shadow-sm"
            />
          ))}
        </div>

        <div className="space-y-4">
          <button type="submit" disabled={loading} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg flex items-center justify-center gap-3 disabled:opacity-50 shadow-xl shadow-indigo-100 active:scale-95 transition-all">
            {loading ? <RefreshCw className="animate-spin" size={20} /> : 'Verify and Access'}
          </button>

          <div className="text-center p-6 bg-gray-50 dark:bg-slate-800/50 rounded-[2rem] border border-gray-100 dark:border-slate-700">
            <p className="text-sm text-slate-500 font-medium mb-2">Didn't receive code?</p>
            <ul className="text-[10px] text-slate-400 font-bold text-left list-disc pl-4 mb-4 space-y-1">
              <li>Check your Spam/Junk folder.</li>
              <li>Wait at least 1 minute for delivery.</li>
              <li>Ensure your email address is correct.</li>
            </ul>
            {timer > 0 ? (
              <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Resend available in {formatTime(timer)}</span>
            ) : (
              <button 
                type="button" 
                onClick={handleResendOtp} 
                disabled={loading}
                className="text-indigo-600 font-black hover:underline flex items-center justify-center gap-2 mx-auto disabled:opacity-50"
              >
                {loading ? <RefreshCw className="animate-spin" size={14} /> : <RefreshCw size={14} />}
                Resend Code Now
              </button>
            )}
          </div>
        </div>
      </form>
    </div>
  );

  return (
    <div className="min-h-screen grid grid-cols-1 lg:grid-cols-2 bg-white text-slate-900 font-sans">
      <div className="hidden lg:flex flex-col justify-between bg-indigo-600 p-16 text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-white/10 rounded-full translate-x-1/2 -translate-y-1/2 blur-3xl"></div>
        <div className="z-10 flex items-center gap-3">
          <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-indigo-600 font-black text-2xl">EA</div>
          <span className="font-bold text-2xl tracking-tight">Expense Analyzer</span>
        </div>
        <div className="z-10 space-y-8 max-w-lg">
          <h1 className="text-6xl font-black leading-tight">Secure Financial Intelligence.</h1>
          <p className="text-xl text-indigo-100 leading-relaxed">Protect your account with enterprise-grade MFA. Verify your identity with a secure code sent to your professional inbox.</p>
        </div>
        <div className="z-10 text-indigo-200 text-sm">&copy; 2025 Expense Analyzer Inc. All rights reserved.</div>
      </div>

      <div className="flex flex-col items-center justify-center p-8 sm:p-12 lg:p-24 bg-gray-50/50">
        {mode === AuthView.VERIFY_OTP ? renderOtpScreen() : (
          <div className="w-full max-w-md space-y-8 animate-in slide-in-from-bottom-4 duration-700">
            <div className="text-center lg:text-left">
              <h2 className="text-3xl font-black">
                {mode === AuthView.LOGIN ? 'Welcome back' : mode === AuthView.SIGNUP ? 'Create account' : 'Reset password'}
              </h2>
              <p className="text-slate-500 mt-2 font-medium">Log in to manage your corporate and personal spending.</p>
              {error && (
                <div className="mt-4 p-4 rounded-2xl bg-rose-50 border border-rose-100 text-rose-600 text-sm font-bold flex items-start gap-3">
                  <AlertCircle className="shrink-0 mt-0.5" size={18} />
                  <span>{error}</span>
                </div>
              )}
            </div>

            <form onSubmit={handleSubmit} className="space-y-5">
              {mode === AuthView.SIGNUP && (
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Full Name</label>
                  <div className="relative">
                    <User className="absolute left-4 top-3.5 text-slate-400" size={18} />
                    <input required type="text" placeholder="John Doe" className="w-full pl-12 pr-4 py-3.5 bg-white border border-gray-100 rounded-2xl focus:ring-4 focus:ring-indigo-100 outline-none shadow-sm" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                  </div>
                </div>
              )}

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Email Address</label>
                <div className="relative">
                  <Mail className="absolute left-4 top-3.5 text-slate-400" size={18} />
                  <input required type="email" placeholder="name@company.com" className="w-full pl-12 pr-4 py-3.5 bg-white border border-gray-100 rounded-2xl focus:ring-4 focus:ring-indigo-100 outline-none shadow-sm" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
                </div>
              </div>

              {mode !== AuthView.FORGOT_PASSWORD && (
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Password</label>
                    {mode === AuthView.LOGIN && <button type="button" onClick={() => setMode(AuthView.FORGOT_PASSWORD)} className="text-xs font-bold text-indigo-600 hover:underline">Forgot password?</button>}
                  </div>
                  <div className="relative">
                    <Lock className="absolute left-4 top-3.5 text-slate-400" size={18} />
                    <input required type="password" placeholder="••••••••" className="w-full pl-12 pr-4 py-3.5 bg-white border border-gray-100 rounded-2xl focus:ring-4 focus:ring-indigo-100 outline-none shadow-sm" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
                  </div>
                </div>
              )}

              <button type="submit" disabled={loading} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg flex items-center justify-center gap-3 disabled:opacity-50 shadow-xl shadow-indigo-100 active:scale-[0.98] transition-all">
                {loading ? <RefreshCw className="animate-spin" size={20} /> : (mode === AuthView.LOGIN ? 'Sign In' : 'Get Started')}
                <ArrowRight size={20} />
              </button>
            </form>

            <p className="text-center text-sm text-slate-500 font-medium">
              {mode === AuthView.LOGIN ? "Don't have an account?" : "Already have an account?"}
              <button onClick={() => setMode(mode === AuthView.LOGIN ? AuthView.SIGNUP : AuthView.LOGIN)} className="ml-2 text-indigo-600 font-black hover:underline">
                {mode === AuthView.LOGIN ? 'Create Account' : 'Sign In'}
              </button>
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AuthPage;

import { GoogleGenAI, Type } from "@google/genai";
import { User } from '../types';

const USERS_KEY = 'ea_mock_users';
const EXPENSES_KEY = 'ea_mock_expenses';
const CATEGORIES_KEY = 'ea_mock_categories';
const OTPS_KEY = 'ea_mock_otps';
const USER_DATA_KEY = 'user';

const getLocalUsers = () => JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
const getLocalExpenses = () => JSON.parse(localStorage.getItem(EXPENSES_KEY) || '[]');
const getLocalCategories = () => JSON.parse(localStorage.getItem(CATEGORIES_KEY) || '[]');
const getLocalOTPs = () => JSON.parse(localStorage.getItem(OTPS_KEY) || '[]');
const getLoggedInUser = () => JSON.parse(localStorage.getItem(USER_DATA_KEY) || 'null');

export const apiService = {
  async post(endpoint: string, data: any) {
    await new Promise(resolve => setTimeout(resolve, 800));
    const currentUser = getLoggedInUser();

    if (endpoint === '/auth/signup') {
      const users = getLocalUsers();
      if (users.find((u: any) => u.email === data.email)) {
        throw new Error('An account with this email already exists.');
      }
      const newUser = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        createdAt: new Date(),
        role: 'Personal User',
        isVerified: false
      };
      users.push(newUser);
      localStorage.setItem(USERS_KEY, JSON.stringify(users));

      const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
      const otps = getLocalOTPs();
      otps.push({ email: data.email, otp: otpCode, expires: Date.now() + 300000 });
      localStorage.setItem(OTPS_KEY, JSON.stringify(otps));

      console.log(`%c[AUTH SERVICE] OTP for ${data.email}: ${otpCode}`, "color: #4f46e5; font-weight: bold; font-size: 14px; background: #eef2ff; padding: 8px; border-radius: 4px;");
      alert(`DEVELOPMENT NOTICE: A verification code ${otpCode} has been sent to ${data.email}. Please check your browser's developer console (F12) to see the code.`);

      return { message: 'OTP sent to your email', email: data.email };
    }

    if (endpoint === '/auth/login') {
      const users = getLocalUsers();
      const user = users.find((u: any) => u.email === data.email && u.password === data.password);
      if (!user) throw new Error('Authentication failed: Invalid credentials.');

      const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
      const otps = getLocalOTPs();
      otps.push({ email: data.email, otp: otpCode, expires: Date.now() + 300000 });
      localStorage.setItem(OTPS_KEY, JSON.stringify(otps));

      console.log(`%c[AUTH SERVICE] Login OTP for ${data.email}: ${otpCode}`, "color: #4f46e5; font-weight: bold; font-size: 14px; background: #eef2ff; padding: 8px; border-radius: 4px;");

      return { requiresVerification: true, email: data.email };
    }

    if (endpoint === '/auth/verify-otp') {
      const otps = getLocalOTPs();
      const record = otps.find((o: any) => o.email === data.email && o.otp === data.otp);

      if (!record) throw new Error('Verification failed: The code you entered is invalid. Please try again.');
      if (Date.now() > record.expires) throw new Error('Verification failed: This code has expired. Please request a new one.');

      const users = getLocalUsers();
      const userIdx = users.findIndex((u: any) => u.email === data.email);
      if (userIdx !== -1) {
        users[userIdx].isVerified = true;
        localStorage.setItem(USERS_KEY, JSON.stringify(users));

        const token = btoa(JSON.stringify({ id: users[userIdx].id, email: users[userIdx].email }));
        const userPublic = { 
          name: users[userIdx].name, 
          email: users[userIdx].email, 
          id: users[userIdx].id, 
          role: users[userIdx].role,
          isVerified: true
        };
        localStorage.setItem(USER_DATA_KEY, JSON.stringify(userPublic));

        const remainingOtps = otps.filter((o: any) => o.email !== data.email);
        localStorage.setItem(OTPS_KEY, JSON.stringify(remainingOtps));

        return { token, user: userPublic };
      }
      throw new Error('Verification failed: User account not found.');
    }

    if (endpoint === '/auth/resend-otp') {
      const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
      const otps = getLocalOTPs().filter((o: any) => o.email !== data.email);
      otps.push({ email: data.email, otp: otpCode, expires: Date.now() + 300000 });
      localStorage.setItem(OTPS_KEY, JSON.stringify(otps));
      console.log(`%c[AUTH SERVICE] Resent OTP for ${data.email}: ${otpCode}`, "color: #4f46e5; font-weight: bold; font-size: 14px; background: #eef2ff; padding: 8px; border-radius: 4px;");
      return { message: 'New code sent' };
    }

    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      const newExpense = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        userId: currentUser.id,
        amount: parseFloat(data.amount),
        status: 'approved' 
      };
      expenses.push(newExpense);
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(expenses));
      return newExpense;
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const newCategory = {
        ...data,
        userId: currentUser.id,
        id: Math.random().toString(36).substr(2, 9),
      };
      categories.push(newCategory);
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(categories));
      return newCategory;
    }

    throw new Error('Endpoint not found');
  },

  async get(endpoint: string) {
    await new Promise(resolve => setTimeout(resolve, 400));
    const currentUser = getLoggedInUser();

    if (endpoint === '/user/me') {
      if (!currentUser) throw new Error('Unauthorized');
      return currentUser;
    }

    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      return expenses.filter((e: any) => e.userId === currentUser.id).reverse();
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);

      const userCategories = categories.filter((c: any) => c.userId === currentUser.id);

      return userCategories.map((cat: any) => {
        const catExpenses = expenses.filter((e: any) => e.category === cat.name);
        const totalSpent = catExpenses.reduce((sum: number, e: any) => sum + e.amount, 0);
        return {
          ...cat,
          spent: totalSpent,
          count: catExpenses.length
        };
      });
    }

    if (endpoint === '/ai/insights') {
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);

      if (expenses.length === 0) {
        return { 
          summary: `Hi ${currentUser.name}, welcome to Expense Analyzer! Start adding your expenses to unlock personalized AI financial insights.`,
          suggestions: ["Add your first expense", "Track your daily commute costs", "Set a grocery budget"]
        };
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const expenseData = expenses.slice(0, 30).map((e: any) => 
          `${e.date}: ₹${e.amount} at ${e.merchant} (${e.category})`
        ).join('\n');

        const response = await ai.models.generateContent({
          model: "gemini-3-flash-preview",
          contents: `User: ${currentUser.name}. Expenses: ${expenseData}. Analyze these expenses in INR. Provide a 1-sentence summary and 3 tips.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.STRING },
                suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["summary", "suggestions"]
            }
          }
        });

        return JSON.parse(response.text || '{}');
      } catch (error) {
        return { summary: "AI insights temporarily unavailable.", suggestions: [] };
      }
    }
    throw new Error('Endpoint not found');
  },

  async delete(endpoint: string) {
    await new Promise(resolve => setTimeout(resolve, 400));

    const currentUser = getLoggedInUser();
    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint.includes('/expenses/')) {
      const id = endpoint.split('/expenses/')[1].split('/')[0];
      const expenses = getLocalExpenses();

      const filtered = expenses.filter((e: any) => {
        const isTarget = String(e.id) === String(id);
        const belongsToUser = String(e.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(EXPENSES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    if (endpoint.includes('/categories/')) {
      const id = endpoint.split('/categories/')[1].split('/')[0];
      const categories = getLocalCategories();

      const filtered = categories.filter((c: any) => {
        const isTarget = String(c.id) === String(id);
        const belongsToUser = String(c.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    throw new Error(`Endpoint not supported: ${endpoint}`);
  }
};

import nodemailer from 'nodemailer';

/**
 * PRODUCTION-READY SMTP CONFIGURATION
 * Optimized for Gmail and high-delivery reliability.
 */
const transporter = nodemailer.createTransport({
  host: process.env.EMAIL_HOST || 'smtp.gmail.com',
  port: parseInt(process.env.EMAIL_PORT || '465'),
  secure: true, // Port 465 requires secure: true
  pool: true, // Maintain persistent connections
  maxConnections: 5,
  auth: {
    user: process.env.EMAIL_USER || 'analyzerexpense60@gmail.com',
    pass: process.env.EMAIL_PASS // Should be the 16-character App Password
  },
  tls: {
    // Helps avoid issues with some hosting environments' certificate chains
    rejectUnauthorized: false
  }
});

/**
 * Sends a high-priority OTP email.
 * @param to Recipient's email address
 * @param otp The 6-digit generated code
 */
export const sendOtpEmail = async (to: string, otp: string): Promise<{ success: boolean; error?: string }> => {
  const fromEmail = process.env.EMAIL_USER || 'analyzerexpense60@gmail.com';

  const mailOptions = {
    from: `"Expense Analyzer Security" <${fromEmail}>`,
    to: to,
    subject: `[Expiring in 1m] ${otp} is your verification code`,
    priority: 'high' as const,
    html: `
      <div style="font-family: 'Segoe UI', Arial, sans-serif; max-width: 500px; margin: 0 auto; padding: 20px; border: 1px solid #eee; border-radius: 15px;">
        <div style="text-align: center; margin-bottom: 20px;">
          <h1 style="color: #4f46e5; margin: 0;">Expense Analyzer</h1>
          <p style="color: #94a3b8; font-size: 12px; text-transform: uppercase; letter-spacing: 1px;">Security Department</p>
        </div>
        <div style="background-color: #f8fafc; padding: 30px; border-radius: 12px; text-align: center;">
          <p style="color: #475569; margin-bottom: 25px;">Hello,<br>Use the code below to verify your account. It is valid for exactly <strong>1 minute</strong>.</p>
          <div style="font-size: 40px; font-weight: 900; letter-spacing: 6px; color: #1e1b4b; margin-bottom: 25px; font-family: monospace;">
            ${otp}
          </div>
          <div style="background-color: #fff1f2; border: 1px solid #fecdd3; padding: 10px; border-radius: 8px;">
            <p style="color: #be123c; font-size: 11px; margin: 0;">
              <strong>Warning:</strong> This code will expire in 60 seconds. Do not share this with anyone.
            </p>
          </div>
        </div>
        <p style="font-size: 11px; color: #94a3b8; text-align: center; margin-top: 20px;">
          If you didn't request this, please change your password immediately.
        </p>
      </div>
    `
  };

  try {
    // Verify transporter configuration on every send for critical bug-fix stability
    await transporter.verify();

    const info = await transporter.sendMail(mailOptions);
    console.log(`✅ OTP sent to ${to}. MessageID: ${info.messageId}`);
    return { success: true };
  } catch (error: any) {
    console.error('❌ EMAIL DELIVERY FAILED:', {
      code: error.code,
      command: error.command,
      response: error.response,
      recipient: to
    });

    let message = 'Mail server connection failed.';
    if (error.code === 'EAUTH') message = 'SMTP Authentication failed. Check App Password.';
    if (error.code === 'ESOCKET') message = 'Connection timed out. Check Firewall/Port 465.';

    return { success: false, error: message };
  }
};

import jwt from 'jsonwebtoken';
import User from '../models/User';
import OTP from '../models/OTP';
import { sendOtpEmail } from '../services/emailService';

const JWT_SECRET = process.env.JWT_SECRET || 'expense-analyzer-secret-key-2025';

// Use standard hashing in production, but keeping it simple for the demo
const hashValue = (val: string) => val; 

export const register = async (req: any, res: any) => {
  try {
    const { name, email, password } = req.body;

    let user = await User.findOne({ email });
    if (user) return res.status(400).json({ message: 'User already exists' });

    user = new User({ name, email, password, isVerified: false });
    await user.save();

    // 6-Digit Code Generation
    const otpCode = Math.floor(100000 + Math.random() * 900000).toString();

    // Strict 1-Minute Expiry
    const expiresAt = new Date(Date.now() + 1 * 60 * 1000); 

    const otpEntry = new OTP({ email, otp: hashValue(otpCode), expiresAt });
    await otpEntry.save();

    const emailResult = await sendOtpEmail(email, otpCode);

    if (!emailResult.success) {
      return res.status(500).json({ 
        message: 'Account created, but we failed to deliver the verification email. Service: ' + emailResult.error,
        email 
      });
    }

    res.json({ message: 'Registration successful. Check your email (valid for 1 min).', email });
  } catch (err) {
    console.error('Registration Error:', err);
    res.status(500).json({ message: 'Registration failed due to a server error.' });
  }
};

export const login = async (req: any, res: any) => {
  try {
    const { email, password } = req.body;
    const user = await User.findOne({ email });

    if (!user || user.password !== password) {
      return res.status(401).json({ message: 'Invalid credentials.' });
    }

    const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
    const expiresAt = new Date(Date.now() + 1 * 60 * 1000); // 1 minute

    await OTP.deleteMany({ email }); // Remove any stale codes
    const otpEntry = new OTP({ email, otp: hashValue(otpCode), expiresAt });
    await otpEntry.save();

    const emailResult = await sendOtpEmail(email, otpCode);

    if (!emailResult.success) {
      return res.status(503).json({ 
        message: 'The email verification service is currently unavailable. Error: ' + emailResult.error 
      });
    }

    res.json({ requiresVerification: true, email });
  } catch (err) {
    console.error('Login Error:', err);
    res.status(500).json({ message: 'Login failed due to a server error.' });
  }
};

export const verifyOtp = async (req: any, res: any) => {
  try {
    const { email, otp } = req.body;
    const otpRecord = await OTP.findOne({ email }).sort({ createdAt: -1 });

    if (!otpRecord) return res.status(400).json({ message: 'No verification record found. Please request a new code.' });
    if (otpRecord.expiresAt < new Date()) return res.status(400).json({ message: 'The verification code has expired (1m limit exceeded).' });

    if (otpRecord.otp !== hashValue(otp)) {
      otpRecord.attempts += 1;
      await otpRecord.save();
      if (otpRecord.attempts >= 3) {
        await OTP.deleteMany({ email });
        return res.status(400).json({ message: 'Too many incorrect attempts. Please request a new code.' });
      }
      return res.status(400).json({ message: 'Invalid verification code.' });
    }

    const user = await User.findOne({ email });
    if (!user) return res.status(404).json({ message: 'User account missing.' });

    user.isVerified = true;
    await user.save();

    const token = jwt.sign({ id: user._id, email: user.email }, JWT_SECRET, { expiresIn: '7d' });
    await OTP.deleteMany({ email });

    res.json({
      token,
      user: {
        id: user._id,
        name: user.name,
        email: user.email,
        role: 'User',
        isVerified: true
      }
    });
  } catch (err) {
    res.status(500).json({ message: 'Verification process failed.' });
  }
};

export const resendOtp = async (req: any, res: any) => {
  try {
    const { email } = req.body;
    const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
    const expiresAt = new Date(Date.now() + 1 * 60 * 1000); // 1 minute

    await OTP.deleteMany({ email });
    const otpEntry = new OTP({ email, otp: hashValue(otpCode), expiresAt });
    await otpEntry.save();

    const emailResult = await sendOtpEmail(email, otpCode);

    if (!emailResult.success) {
      return res.status(503).json({ message: 'Could not deliver email: ' + emailResult.error });
    }

    res.json({ message: 'A new 6-digit code has been sent (valid for 1 min).' });
  } catch (err) {
    res.status(500).json({ message: 'Failed to resend code.' });
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { User } from '../types';

const USERS_KEY = 'ea_mock_users';
const EXPENSES_KEY = 'ea_mock_expenses';
const CATEGORIES_KEY = 'ea_mock_categories';
const OTPS_KEY = 'ea_mock_otps';
const USER_DATA_KEY = 'user';

const getLocalUsers = () => JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
const getLocalExpenses = () => JSON.parse(localStorage.getItem(EXPENSES_KEY) || '[]');
const getLocalCategories = () => JSON.parse(localStorage.getItem(CATEGORIES_KEY) || '[]');
const getLocalOTPs = () => JSON.parse(localStorage.getItem(OTPS_KEY) || '[]');
const getLoggedInUser = () => JSON.parse(localStorage.getItem(USER_DATA_KEY) || 'null');

export const apiService = {
  async post(endpoint: string, data: any) {
    await new Promise(resolve => setTimeout(resolve, 800));
    const currentUser = getLoggedInUser();

    if (endpoint === '/auth/signup') {
      const users = getLocalUsers();
      if (users.find((u: any) => u.email === data.email)) {
        throw new Error('An account with this email already exists.');
      }
      const newUser = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        createdAt: new Date(),
        role: 'Personal User',
        isVerified: false
      };
      users.push(newUser);
      localStorage.setItem(USERS_KEY, JSON.stringify(users));

      const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
      const otps = getLocalOTPs();
      // Mocking 1 minute expiry for frontend-only mode
      otps.push({ email: data.email, otp: otpCode, expires: Date.now() + 60000 });
      localStorage.setItem(OTPS_KEY, JSON.stringify(otps));

      console.log(`%c[AUTH SERVICE] New OTP for ${data.email}: ${otpCode}`, "color: #4f46e5; font-weight: bold; font-size: 14px; background: #eef2ff; padding: 8px; border-radius: 4px;");
      alert(`DEVELOPMENT: Code ${otpCode} sent to ${data.email}. EXPIRES IN 1 MINUTE. Check console (F12) if alert is closed.`);

      return { message: 'OTP sent to your email', email: data.email };
    }

    if (endpoint === '/auth/login') {
      const users = getLocalUsers();
      const user = users.find((u: any) => u.email === data.email && u.password === data.password);
      if (!user) throw new Error('Authentication failed: Invalid credentials.');

      const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
      const otps = getLocalOTPs();
      otps.push({ email: data.email, otp: otpCode, expires: Date.now() + 60000 });
      localStorage.setItem(OTPS_KEY, JSON.stringify(otps));

      console.log(`%c[AUTH SERVICE] Login OTP for ${data.email}: ${otpCode}`, "color: #4f46e5; font-weight: bold; font-size: 14px; background: #eef2ff; padding: 8px; border-radius: 4px;");

      return { requiresVerification: true, email: data.email };
    }

    if (endpoint === '/auth/verify-otp') {
      const otps = getLocalOTPs();
      const record = otps.find((o: any) => o.email === data.email && o.otp === data.otp);

      if (!record) throw new Error('Invalid code.');
      if (Date.now() > record.expires) throw new Error('Verification failed: Code has expired (1 minute limit).');

      const users = getLocalUsers();
      const userIdx = users.findIndex((u: any) => u.email === data.email);
      if (userIdx !== -1) {
        users[userIdx].isVerified = true;
        localStorage.setItem(USERS_KEY, JSON.stringify(users));

        const token = btoa(JSON.stringify({ id: users[userIdx].id, email: users[userIdx].email }));
        const userPublic = { 
          name: users[userIdx].name, 
          email: users[userIdx].email, 
          id: users[userIdx].id, 
          role: users[userIdx].role,
          isVerified: true
        };
        localStorage.setItem(USER_DATA_KEY, JSON.stringify(userPublic));

        const remainingOtps = otps.filter((o: any) => o.email !== data.email);
        localStorage.setItem(OTPS_KEY, JSON.stringify(remainingOtps));

        return { token, user: userPublic };
      }
      throw new Error('Verification failed: User account not found.');
    }

    if (endpoint === '/auth/resend-otp') {
      const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
      const otps = getLocalOTPs().filter((o: any) => o.email !== data.email);
      otps.push({ email: data.email, otp: otpCode, expires: Date.now() + 60000 });
      localStorage.setItem(OTPS_KEY, JSON.stringify(otps));
      console.log(`%c[AUTH SERVICE] Resent OTP for ${data.email}: ${otpCode}`, "color: #4f46e5; font-weight: bold; font-size: 14px; background: #eef2ff; padding: 8px; border-radius: 4px;");
      return { message: 'New code sent (1m validity)' };
    }

    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      const newExpense = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        userId: currentUser.id,
        amount: parseFloat(data.amount),
        status: 'approved' 
      };
      expenses.push(newExpense);
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(expenses));
      return newExpense;
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const newCategory = {
        ...data,
        userId: currentUser.id,
        id: Math.random().toString(36).substr(2, 9),
      };
      categories.push(newCategory);
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(categories));
      return newCategory;
    }

    throw new Error('Endpoint not found');
  },

  async get(endpoint: string) {
    await new Promise(resolve => setTimeout(resolve, 400));
    const currentUser = getLoggedInUser();

    if (endpoint === '/user/me') {
      if (!currentUser) throw new Error('Unauthorized');
      return currentUser;
    }

    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      return expenses.filter((e: any) => e.userId === currentUser.id).reverse();
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);

      const userCategories = categories.filter((c: any) => c.userId === currentUser.id);

      return userCategories.map((cat: any) => {
        const catExpenses = expenses.filter((e: any) => e.category === cat.name);
        const totalSpent = catExpenses.reduce((sum: number, e: any) => sum + e.amount, 0);
        return {
          ...cat,
          spent: totalSpent,
          count: catExpenses.length
        };
      });
    }

    if (endpoint === '/ai/insights') {
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);

      if (expenses.length === 0) {
        return { 
          summary: `Hi ${currentUser.name}, welcome to Expense Analyzer! Start adding your expenses to unlock personalized AI financial insights.`,
          suggestions: ["Add your first expense", "Track your daily commute costs", "Set a grocery budget"]
        };
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const expenseData = expenses.slice(0, 30).map((e: any) => 
          `${e.date}: ₹${e.amount} at ${e.merchant} (${e.category})`
        ).join('\n');

        const response = await ai.models.generateContent({
          model: "gemini-3-flash-preview",
          contents: `User: ${currentUser.name}. Expenses: ${expenseData}. Analyze these expenses in INR. Provide a 1-sentence summary and 3 tips.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.STRING },
                suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["summary", "suggestions"]
            }
          }
        });

        return JSON.parse(response.text || '{}');
      } catch (error) {
        return { summary: "AI insights temporarily unavailable.", suggestions: [] };
      }
    }
    throw new Error('Endpoint not found');
  },

  async delete(endpoint: string) {
    await new Promise(resolve => setTimeout(resolve, 400));

    const currentUser = getLoggedInUser();
    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint.includes('/expenses/')) {
      const id = endpoint.split('/expenses/')[1].split('/')[0];
      const expenses = getLocalExpenses();

      const filtered = expenses.filter((e: any) => {
        const isTarget = String(e.id) === String(id);
        const belongsToUser = String(e.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(EXPENSES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    if (endpoint.includes('/categories/')) {
      const id = endpoint.split('/categories/')[1].split('/')[0];
      const categories = getLocalCategories();

      const filtered = categories.filter((c: any) => {
        const isTarget = String(c.id) === String(id);
        const belongsToUser = String(c.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    throw new Error(`Endpoint not supported: ${endpoint}`);
  }
};

import mongoose from 'mongoose';

const OTPSchema = new mongoose.Schema({
  email: { type: String, required: true },
  otp: { type: String, required: true },
  expiresAt: { type: Date, required: true },
  attempts: { type: Number, default: 0 },
  createdAt: { type: Date, default: Date.now, expires: 60 } // Automatically remove record after 60s
});

export default mongoose.model('OTP', OTPSchema);

