import { GoogleGenAI, Type } from "@google/genai";
import { User } from '../types';
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  sendEmailVerification,
  updateProfile,
  signOut
} from "firebase/auth";
import { auth } from './firebase';

const EXPENSES_KEY = 'ea_mock_expenses';
const CATEGORIES_KEY = 'ea_mock_categories';
const USER_DATA_KEY = 'user';

const getLocalExpenses = () => JSON.parse(localStorage.getItem(EXPENSES_KEY) || '[]');
const getLocalCategories = () => JSON.parse(localStorage.getItem(CATEGORIES_KEY) || '[]');
const getLoggedInUser = () => JSON.parse(localStorage.getItem(USER_DATA_KEY) || 'null');

export const apiService = {
  async post(endpoint: string, data: any) {
    if (endpoint === '/auth/signup') {
      try {
        const userCredential = await createUserWithEmailAndPassword(auth, data.email, data.password);
        await updateProfile(userCredential.user, { displayName: data.name });
        await sendEmailVerification(userCredential.user);
        return { message: 'Verification email sent', email: data.email };
      } catch (error: any) {
        throw new Error(error.message || 'Signup failed');
      }
    }

    if (endpoint === '/auth/login') {
      try {
        const userCredential = await signInWithEmailAndPassword(auth, data.email, data.password);
        const user = userCredential.user;

        if (!user.emailVerified) {
          throw new Error('Please verify your email address before logging in. Check your inbox.');
        }

        const userPublic = { 
          name: user.displayName || 'User', 
          email: user.email || '', 
          id: user.uid, 
          role: 'Personal User',
          isVerified: true
        };

        localStorage.setItem(USER_DATA_KEY, JSON.stringify(userPublic));
        localStorage.setItem('token', await user.getIdToken());

        return { user: userPublic };
      } catch (error: any) {
        if (error.message.includes('verify')) throw error;
        throw new Error('Authentication failed: Invalid credentials.');
      }
    }

    if (endpoint === '/auth/check-verification') {
      await auth.currentUser?.reload();
      const user = auth.currentUser;
      if (user?.emailVerified) {
        const userPublic = { 
          name: user.displayName || 'User', 
          email: user.email || '', 
          id: user.uid, 
          role: 'Personal User',
          isVerified: true
        };
        localStorage.setItem(USER_DATA_KEY, JSON.stringify(userPublic));
        localStorage.setItem('token', await user.getIdToken());
        return { verified: true, user: userPublic };
      }
      return { verified: false };
    }

    if (endpoint === '/auth/resend-verification') {
      if (auth.currentUser) {
        await sendEmailVerification(auth.currentUser);
        return { message: 'Verification email resent' };
      }
      throw new Error('No user logged in to verify');
    }

    const currentUser = getLoggedInUser();
    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      const newExpense = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        userId: currentUser.id,
        amount: parseFloat(data.amount),
        status: 'approved' 
      };
      expenses.push(newExpense);
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(expenses));
      return newExpense;
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const newCategory = {
        ...data,
        userId: currentUser.id,
        id: Math.random().toString(36).substr(2, 9),
      };
      categories.push(newCategory);
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(categories));
      return newCategory;
    }

    throw new Error('Endpoint not found');
  },

  async get(endpoint: string) {
    const currentUser = getLoggedInUser();

    if (endpoint === '/user/me') {
      if (!currentUser) throw new Error('Unauthorized');
      return currentUser;
    }

    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      return expenses.filter((e: any) => e.userId === currentUser.id).reverse();
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);
      const userCategories = categories.filter((c: any) => c.userId === currentUser.id);

      return userCategories.map((cat: any) => {
        const catExpenses = expenses.filter((e: any) => e.category === cat.name);
        const totalSpent = catExpenses.reduce((sum: number, e: any) => sum + e.amount, 0);
        return { ...cat, spent: totalSpent, count: catExpenses.length };
      });
    }

    if (endpoint === '/ai/insights') {
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);
      if (expenses.length === 0) {
        return { 
          summary: `Hi ${currentUser.name}, welcome! Add expenses to unlock AI insights.`,
          suggestions: ["Add your first expense", "Check category trends"]
        };
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const expenseData = expenses.slice(0, 30).map((e: any) => 
          `${e.date}: ₹${e.amount} at ${e.merchant} (${e.category})`
        ).join('\n');

        const response = await ai.models.generateContent({
          model: "gemini-3-flash-preview",
          contents: `User: ${currentUser.name}. Expenses: ${expenseData}. Analyze in INR. 1-sentence summary, 3 tips.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.STRING },
                suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["summary", "suggestions"]
            }
          }
        });

        return JSON.parse(response.text || '{}');
      } catch (error) {
        return { summary: "AI insights temporarily unavailable.", suggestions: [] };
      }
    }
    throw new Error('Endpoint not found');
  },

  async delete(endpoint: string) {
    const currentUser = getLoggedInUser();
    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint.includes('/expenses/')) {
      const id = endpoint.split('/expenses/')[1].split('/')[0];
      const expenses = getLocalExpenses();
      const filtered = expenses.filter((e: any) => !(String(e.id) === String(id) && String(e.userId) === String(currentUser.id)));
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    if (endpoint.includes('/categories/')) {
      const id = endpoint.split('/categories/')[1].split('/')[0];
      const categories = getLocalCategories();
      const filtered = categories.filter((c: any) => !(String(c.id) === String(id) && String(c.userId) === String(currentUser.id)));
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(filtered));
      return { success: true };
    }
    throw new Error(`Endpoint not supported`);
  },

  async logout() {
    await signOut(auth);
    localStorage.removeItem(USER_DATA_KEY);
    localStorage.removeItem('token');
  }
};

import React, { useState, useEffect } from 'react';
import { AuthView, User as UserType } from '../types';
import { Shield, Mail, Lock, User, ArrowRight, ShieldCheck, RefreshCw, ChevronLeft, AlertCircle, Inbox } from 'lucide-react';
import { apiService } from '../services/api';

interface AuthPageProps {
  mode: AuthView;
  setMode: (mode: AuthView) => void;
  onLogin: (user: UserType) => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ mode, setMode, onLogin }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccessMsg('');

    try {
      if (mode === AuthView.LOGIN) {
        const data = await apiService.post('/auth/login', { email: formData.email, password: formData.password });
        onLogin(data.user);
      } else if (mode === AuthView.SIGNUP) {
        await apiService.post('/auth/signup', formData);
        setMode(AuthView.VERIFY_OTP); // Now acts as "Verify Email" screen
        setSuccessMsg('A verification link has been sent to your email.');
      }
    } catch (err: any) {
      setError(err.message || 'Authentication failed');
    } finally {
      setLoading(false);
    }
  };

  const handleResendLink = async () => {
    setLoading(true);
    setError('');
    setSuccessMsg('');
    try {
      await apiService.post('/auth/resend-verification', { email: formData.email });
      setSuccessMsg('Verification link resent successfully!');
    } catch (err: any) {
      setError(err.message || 'Resend failed');
    } finally {
      setLoading(false);
    }
  };

  const checkVerificationStatus = async () => {
    setLoading(true);
    try {
      const data = await apiService.post('/auth/check-verification', {});
      if (data.verified) {
        onLogin(data.user);
      } else {
        setError('Email not yet verified. Please click the link in your inbox.');
      }
    } catch (err: any) {
      setError(err.message || 'Failed to check status');
    } finally {
      setLoading(false);
    }
  };

  const renderVerifyScreen = () => (
    <div className="w-full max-w-md space-y-8 animate-in slide-in-from-bottom-4 duration-700">
      <div className="text-center lg:text-left">
        <button onClick={() => setMode(AuthView.LOGIN)} className="flex items-center gap-2 text-sm font-bold text-slate-500 hover:text-indigo-600 transition-colors mb-4">
