        return { ...cat, spent: totalSpent, count: catExpenses.length };
      });
    }

    if (endpoint === '/ai/insights') {
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);
      if (expenses.length === 0) {
        return { 
          summary: `Hi ${currentUser.name}, welcome! Add expenses to unlock AI insights.`,
          suggestions: ["Add your first expense", "Check category trends"]
        };
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const expenseData = expenses.slice(0, 30).map((e: any) => 
          `${e.date}: ₹${e.amount} at ${e.merchant} (${e.category})`
        ).join('\n');

        const response = await ai.models.generateContent({
          model: "gemini-3-flash-preview",
          contents: `User: ${currentUser.name}. Expenses: ${expenseData}. Analyze in INR. 1-sentence summary, 3 tips.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.STRING },
                suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["summary", "suggestions"]
            }
          }
        });

        return JSON.parse(response.text || '{}');
      } catch (error) {
        return { summary: "AI insights temporarily unavailable.", suggestions: [] };
      }
    }
    throw new Error('Endpoint not found');
  },

  async delete(endpoint: string) {
    const currentUser = getLoggedInUser();
    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint.includes('/expenses/')) {
      const id = endpoint.split('/expenses/')[1].split('/')[0];
      const expenses = getLocalExpenses();
      const filtered = expenses.filter((e: any) => !(String(e.id) === String(id) && String(e.userId) === String(currentUser.id)));
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    if (endpoint.includes('/categories/')) {
      const id = endpoint.split('/categories/')[1].split('/')[0];
      const categories = getLocalCategories();
      const filtered = categories.filter((c: any) => !(String(c.id) === String(id) && String(c.userId) === String(currentUser.id)));
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(filtered));
      return { success: true };
    }
    throw new Error(`Endpoint not supported`);
  },

  async logout() {
    try {
      await signOut(auth);
    } catch (e) {
      console.warn("SignOut failed but continuing local cleanup:", e);
    }
    localStorage.removeItem(USER_DATA_KEY);
    localStorage.removeItem('token');
  }
};

