import { GoogleGenAI, Type } from "@google/genai";
import { Expense } from '../types';

const USERS_KEY = 'ea_mock_users';
const EXPENSES_KEY = 'ea_mock_expenses';
const CATEGORIES_KEY = 'ea_mock_categories';
const USER_DATA_KEY = 'user';

const getLocalUsers = () => JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
const getLocalExpenses = () => JSON.parse(localStorage.getItem(EXPENSES_KEY) || '[]');
const getLocalCategories = () => JSON.parse(localStorage.getItem(CATEGORIES_KEY) || '[]');
const getLoggedInUser = () => JSON.parse(localStorage.getItem(USER_DATA_KEY) || 'null');

const DEFAULT_CATEGORIES = [
  { name: 'Food & Dining', iconName: 'Utensils', color: 'emerald', budget: 5000 },
  { name: 'Transport', iconName: 'Car', color: 'blue', budget: 3000 },
  { name: 'Shopping', iconName: 'ShoppingBag', color: 'rose', budget: 10000 },
  { name: 'Bills & Utilities', iconName: 'Zap', color: 'amber', budget: 2000 },
];

export const apiService = {
  async post(endpoint: string, data: any) {
    await new Promise(resolve => setTimeout(resolve, 600));
    const currentUser = getLoggedInUser();

    if (endpoint === '/auth/signup') {
      const users = getLocalUsers();
      if (users.find((u: any) => u.email === data.email)) {
        throw new Error('An account with this email already exists.');
      }
      const newUser = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        createdAt: new Date(),
        role: 'Personal User'
      };
      users.push(newUser);
      localStorage.setItem(USERS_KEY, JSON.stringify(users));

      // Seed default categories for new user
      const allCategories = getLocalCategories();
      const userDefaults = DEFAULT_CATEGORIES.map(cat => ({
        ...cat,
        userId: newUser.id,
        id: Math.random().toString(36).substr(2, 9),
      }));
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify([...allCategories, ...userDefaults]));

      return { message: 'Registration successful' };
    }

    if (endpoint === '/auth/login') {
      const users = getLocalUsers();
      const user = users.find((u: any) => u.email === data.email && u.password === data.password);
      if (!user) throw new Error('Invalid email or password credentials.');

      const token = btoa(JSON.stringify({ id: user.id, email: user.email }));
      const userPublic = { name: user.name, email: user.email, id: user.id, role: user.role };
      localStorage.setItem(USER_DATA_KEY, JSON.stringify(userPublic));
      return { token, user: userPublic };
    }

    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      const newExpense = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        userId: currentUser.id,
        amount: parseFloat(data.amount),
        status: 'approved' 
      };
      expenses.push(newExpense);
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(expenses));
      return newExpense;
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const newCategory = {
        ...data,
        userId: currentUser.id,
        id: Math.random().toString(36).substr(2, 9),
      };
      categories.push(newCategory);
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(categories));
      return newCategory;
    }

    throw new Error('Endpoint not found');
  },

  async put(endpoint: string, data: any) {
    await new Promise(resolve => setTimeout(resolve, 400));
    const currentUser = getLoggedInUser();
    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint.startsWith('/expenses/')) {
      const id = endpoint.split('/expenses/')[1];
      const expenses = getLocalExpenses();
      const index = expenses.findIndex((e: any) => String(e.id) === String(id) && String(e.userId) === String(currentUser.id));

      if (index === -1) throw new Error('Expense not found');

      const updatedExpense = { ...expenses[index], ...data, amount: parseFloat(data.amount) };
      expenses[index] = updatedExpense;
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(expenses));
      return updatedExpense;
    }

    throw new Error('Endpoint not found');
  },

  async get(endpoint: string) {
    await new Promise(resolve => setTimeout(resolve, 400));
    const currentUser = getLoggedInUser();

    if (endpoint === '/user/me') {
      if (!currentUser) throw new Error('Unauthorized');
      return currentUser;
    }

    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      return expenses.filter((e: any) => e.userId === currentUser.id).reverse();
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);

      let userCategories = categories.filter((c: any) => c.userId === currentUser.id);

      // If no categories, seed them on the fly for better UX
      if (userCategories.length === 0) {
        const userDefaults = DEFAULT_CATEGORIES.map(cat => ({
          ...cat,
          userId: currentUser.id,
          id: Math.random().toString(36).substr(2, 9),
        }));
        const allCategories = getLocalCategories();
        localStorage.setItem(CATEGORIES_KEY, JSON.stringify([...allCategories, ...userDefaults]));
        userCategories = userDefaults;
      }

      return userCategories.map((cat: any) => {
        const catExpenses = expenses.filter((e: any) => e.category === cat.name);
        const totalSpent = catExpenses.reduce((sum: number, e: any) => sum + e.amount, 0);
        return {
          ...cat,
          spent: totalSpent,
          count: catExpenses.length
        };
      });
    }

    if (endpoint === '/ai/insights') {
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);

      if (expenses.length === 0) {
        return { 
          summary: `Hi ${currentUser.name}, welcome to Expense Analyzer! Start adding your expenses to unlock personalized AI financial insights.`,
          suggestions: ["Add your first expense", "Track your daily commute costs", "Set a grocery budget"]
        };
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const expenseData = expenses.slice(0, 30).map((e: any) => 
          `${e.date}: ₹${e.amount} at ${e.merchant} (${e.category})`
        ).join('\n');

        const response = await ai.models.generateContent({
          model: "gemini-3-flash-preview",
          contents: `User: ${currentUser.name}. Expenses: ${expenseData}. Analyze these expenses in INR. Provide a 1-sentence summary and 3 tips.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.STRING },
                suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["summary", "suggestions"]
            }
          }
        });

        return JSON.parse(response.text || '{}');
      } catch (error) {
        return { summary: "AI insights temporarily unavailable.", suggestions: [] };
      }
    }
    throw new Error('Endpoint not found');
  },

  async delete(endpoint: string) {
    await new Promise(resolve => setTimeout(resolve, 400));

    const currentUser = getLoggedInUser();
    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint.includes('/expenses/')) {
      const id = endpoint.split('/expenses/')[1].split('/')[0];
      const expenses = getLocalExpenses();

      const filtered = expenses.filter((e: any) => {
        const isTarget = String(e.id) === String(id);
        const belongsToUser = String(e.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(EXPENSES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    if (endpoint.includes('/categories/')) {
      const id = endpoint.split('/categories/')[1].split('/')[0];
      const categories = getLocalCategories();

      const filtered = categories.filter((c: any) => {
        const isTarget = String(c.id) === String(id);
        const belongsToUser = String(c.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    throw new Error(`Endpoint not supported: ${endpoint}`);
  }
};

import React, { useState, useEffect } from 'react';
import { Plus, Filter, Search, Download, Trash2, Edit3, MoreVertical, X, Upload, Receipt, Check, FileText, Grid, Wallet, CreditCard, Banknote } from 'lucide-react';
import { apiService } from '../services/api';
import { Expense, ExpenseMode, AppView } from '../types';

interface ExpenseManagerProps {
  mode: ExpenseMode;
  onNavigate?: (view: AppView) => void;
}

const ExpenseManager: React.FC<ExpenseManagerProps> = ({ mode, onNavigate }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [showFilters, setShowFilters] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [userCategories, setUserCategories] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDeleting, setIsDeleting] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    amount: '',
    merchant: '',
    category: '',
    paymentMethod: 'UPI',
    notes: ''
  });

  useEffect(() => {
    fetchExpenses();
    fetchUserCategories();
  }, []);

  const fetchExpenses = async () => {
    setIsLoading(true);
    try {
      const data = await apiService.get('/expenses');
      setExpenses(data);
    } catch (err) {
      console.error('Failed to fetch expenses', err);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchUserCategories = async () => {
    try {
      const cats = await apiService.get('/categories');
      setUserCategories(cats);
      if (cats.length > 0 && !formData.category) {
        setFormData(prev => ({ ...prev, category: cats[0].name }));
      }
    } catch (err) {
      console.error('Failed to fetch categories');
    }
  };

  const handleSaveExpense = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.category) {
      alert('Please select a category. If none exist, create one in the Categories tab.');
      return;
    }

    try {
      if (editingExpense) {
        const updated = await apiService.put(`/expenses/${editingExpense.id}`, formData);
        setExpenses(prev => prev.map(exp => exp.id === updated.id ? updated : exp));
      } else {
        const newExpense = await apiService.post('/expenses', formData);
        setExpenses(prev => [newExpense, ...prev]);
      }

      closeModal();
    } catch (err) {
      alert('Error saving expense');
    }
  };

  const handleEditClick = (expense: Expense) => {
    setEditingExpense(expense);
    setFormData({
      date: expense.date,
      amount: expense.amount.toString(),
      merchant: expense.merchant,
      category: expense.category,
      paymentMethod: expense.paymentMethod,
      notes: expense.notes || ''
    });
    setShowAddModal(true);
  };

  const closeModal = () => {
    setShowAddModal(false);
    setEditingExpense(null);
    setFormData({
      date: new Date().toISOString().split('T')[0],
      amount: '',
      merchant: '',
      category: userCategories.length > 0 ? userCategories[0].name : '',
      paymentMethod: 'UPI',
      notes: ''
    });
  };

  const handleDelete = async (id: string) => {
    if (!id) return;
    if (!window.confirm('Are you sure you want to delete this transaction permanently?')) return;

    setIsDeleting(id);
    try {
      await apiService.delete(`/expenses/${id}`);
      setExpenses(prev => prev.filter(e => String(e.id) !== String(id)));
    } catch (err) {
      console.error('Delete error:', err);
      alert('Failed to delete the transaction. Please try again.');
    } finally {
      setIsDeleting(null);
    }
  };

  const isCompany = mode === ExpenseMode.COMPANY;
  const themeBgBtn = isCompany ? 'bg-indigo-600' : 'bg-emerald-600';

  const filteredExpenses = expenses.filter(e => {
    const matchesSearch = e.merchant.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         e.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || e.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="space-y-6 sm:space-y-8">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black tracking-tighter">{isCompany ? 'Company Claims' : 'Personal Expenses'}</h1>
          <p className="text-slate-500 text-sm font-medium mt-1">Efficiently track your ₹ INR spending.</p>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setShowAddModal(true)} className={`px-8 py-3 ${themeBgBtn} text-white rounded-2xl text-sm font-black shadow-lg transition-all active:scale-95`}>
            Add Expense
          </button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-800 p-6 rounded-[2.5rem] border border-gray-100 flex flex-col md:flex-row gap-4 items-center shadow-sm">
        <div className="relative flex-1 w-full">
          <Search size={18} className="absolute left-4 top-3.5 text-slate-400" />
          <input type="text" placeholder="Search expenses..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-12 pr-4 py-3.5 bg-gray-50 dark:bg-slate-900 border rounded-2xl outline-none" />
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          <select 
            value={selectedCategory} 
            onChange={e => setSelectedCategory(e.target.value)}
            className="px-4 py-3.5 bg-gray-50 dark:bg-slate-900 border rounded-2xl text-sm font-bold outline-none grow md:grow-0"
          >
            <option>All</option>
            {userCategories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
          </select>
          <button onClick={() => setShowFilters(!showFilters)} className={`px-6 py-3.5 bg-gray-50 border rounded-2xl text-sm font-black`}>Filter</button>
        </div>
