                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Date</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Merchant</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Category</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Method</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Amount</th>
                <th className="px-8 py-5"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-slate-700">
              {isLoading ? (
                <tr><td colSpan={6} className="px-8 py-20 text-center font-bold text-slate-400">Loading transactions...</td></tr>
              ) : filteredExpenses.length === 0 ? (
                <tr><td colSpan={6} className="px-8 py-20 text-center text-slate-400 italic font-medium">No expenses found matching your criteria.</td></tr>
              ) : filteredExpenses.map(expense => (
                <tr key={expense.id} className={`hover:bg-gray-50 dark:hover:bg-slate-700/50 transition-colors group ${isDeleting === expense.id ? 'opacity-30' : ''}`}>
                  <td className="px-8 py-6 text-sm font-bold text-slate-400">{new Date(expense.date).toLocaleDateString()}</td>
                  <td className="px-8 py-6 font-black">{expense.merchant}</td>
                  <td className="px-8 py-6">
                    <span className="px-3 py-1 bg-gray-100 dark:bg-slate-700 rounded-lg text-[10px] font-black uppercase tracking-widest text-slate-500">
                      {expense.category}
                    </span>
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-2">
                      <span className="px-3 py-1 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 rounded-lg text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5">
                        {expense.paymentMethod}
                      </span>
                    </div>
                  </td>
                  <td className="px-8 py-6 text-sm font-black">₹{expense.amount.toLocaleString('en-IN')}</td>
                  <td className="px-8 py-6 text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button 
                        onClick={() => handleEditClick(expense)}
                        className="p-2 text-slate-400 hover:text-indigo-600 transition-colors"
                        title="Edit Transaction"
                      >
                        <Edit3 size={18} />
                      </button>
                      <button 
                        onClick={() => handleDelete(expense.id)} 
                        disabled={isDeleting === expense.id}
                        className="p-2 text-slate-400 hover:text-rose-600 disabled:opacity-50 transition-colors"
                        title="Delete Transaction"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md transition-all">
          <form onSubmit={handleSaveExpense} className="bg-white dark:bg-slate-800 w-full max-w-2xl max-h-[90vh] rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 flex flex-col">
            <div className="p-6 sm:p-10 border-b dark:border-slate-700 flex items-center justify-between shrink-0">
              <h2 className="text-2xl font-black">{editingExpense ? 'Edit Expense' : 'Add Expense'} (₹ INR)</h2>
              <button type="button" onClick={closeModal} className="p-2 hover:bg-gray-100 dark:hover:bg-slate-700 rounded-xl transition-colors"><X size={20} /></button>
            </div>

            <div className="p-10 space-y-6 overflow-y-auto custom-scrollbar flex-1">
              {userCategories.length === 0 ? (
                <div className="p-12 bg-amber-50 dark:bg-amber-900/20 border-2 border-dashed border-amber-200 dark:border-amber-800 rounded-[2rem] text-center space-y-6">
                  <Grid size={48} className="mx-auto text-amber-500" />
                  <div>
                    <p className="text-amber-800 dark:text-amber-400 font-black text-xl">No Categories Found</p>
                    <p className="text-sm text-amber-700 dark:text-amber-500 mt-2 max-w-sm mx-auto">You must have at least one category before you can log an expense. We usually create these for you automatically.</p>
                  </div>
                  <button 
                    type="button" 
                    onClick={() => { closeModal(); onNavigate?.(AppView.CATEGORIES); }}
                    className="px-8 py-3 bg-amber-600 text-white rounded-2xl font-black text-sm shadow-lg hover:bg-amber-700 transition-all"
                  >
                    Manage Categories
                  </button>
                </div>
              ) : (
                <>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Date</label>
                      <input required type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full p-4 bg-gray-50 dark:bg-slate-900 rounded-2xl border dark:border-slate-700 outline-none focus:ring-4 focus:ring-emerald-500/10" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Amount (₹)</label>
                      <input required type="number" step="0.01" placeholder="0.00" value={formData.amount} onChange={e => setFormData({...formData, amount: e.target.value})} className="w-full p-4 bg-gray-50 dark:bg-slate-900 rounded-2xl border dark:border-slate-700 outline-none focus:ring-4 focus:ring-emerald-500/10" />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Merchant / Store</label>
                    <input required type="text" placeholder="e.g. Amazon, Starbucks, Uber" value={formData.merchant} onChange={e => setFormData({...formData, merchant: e.target.value})} className="w-full p-4 bg-gray-50 dark:bg-slate-900 rounded-2xl border dark:border-slate-700 outline-none focus:ring-4 focus:ring-emerald-500/10" />
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Select Category</label>
                    <select required value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} className="w-full p-4 bg-gray-50 dark:bg-slate-900 rounded-2xl border dark:border-slate-700 outline-none focus:ring-4 focus:ring-emerald-500/10">
                      {userCategories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                    </select>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Payment Method</label>
                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                      {['UPI', 'Credit Card', 'Cash', 'Net Banking'].map(method => (
                        <button
                          key={method}
                          type="button"
                          onClick={() => setFormData({...formData, paymentMethod: method})}
                          className={`py-3 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all ${
                            formData.paymentMethod === method 
                            ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' 
                            : 'bg-white dark:bg-slate-900 border-gray-100 dark:border-slate-700 text-slate-500 hover:border-emerald-500'
                          }`}
                        >
                          {method}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Notes (Optional)</label>
                    <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} placeholder="Add extra details..." className="w-full p-4 bg-gray-50 dark:bg-slate-900 rounded-2xl border dark:border-slate-700 outline-none h-24 resize-none focus:ring-4 focus:ring-emerald-500/10" />
                  </div>
                </>
              )}
            </div>

            <div className="p-8 sm:p-10 bg-gray-50 dark:bg-slate-900/50 flex flex-col sm:flex-row justify-end gap-3 shrink-0">
              <button type="button" onClick={closeModal} className="px-8 py-4 font-black hover:bg-gray-100 dark:hover:bg-slate-700 rounded-2xl transition-colors">Cancel</button>
              {userCategories.length > 0 && (
                <button type="submit" className={`px-10 py-4 ${themeBgBtn} text-white rounded-2xl font-black shadow-xl hover:brightness-110 active:scale-95 transition-all`}>
                  {editingExpense ? 'Update Transaction' : 'Save Transaction'}
                </button>
              )}
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

export default ExpenseManager;

import React, { useState, useEffect } from 'react';
import { AppView, AuthView, ExpenseMode, User } from './types';
import Layout from './components/Layout';
import AuthPage from './components/Auth';
import SelectionScreen from './components/SelectionScreen';
import Dashboard from './components/Dashboard';
import ExpenseManager from './components/ExpenseManager';
import BudgetTracker from './components/BudgetTracker';
import Reports from './components/Reports';
import Approvals from './components/Approvals';
import Reimbursements from './components/Reimbursements';
import AiInsights from './components/AiInsights';
import Settings from './components/Settings';
import Categories from './components/Categories';
import Subscriptions from './components/Subscriptions';
import SavingsGoals from './components/SavingsGoals';
import { apiService } from './services/api';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(!!localStorage.getItem('token'));
  const [user, setUser] = useState<User | null>(null);
  const [expenseMode, setExpenseMode] = useState<ExpenseMode | null>(null);
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [authMode, setAuthMode] = useState<AuthView>(AuthView.LOGIN);
  const [isDarkMode, setIsDarkMode] = useState<boolean>(false);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const loadUser = async () => {
      if (isAuthenticated) {
        try {
          const userData = await apiService.get('/user/me');
          setUser(userData);
        } catch (err) {
          localStorage.removeItem('token');
          localStorage.removeItem('user');
          setIsAuthenticated(false);
        }
      }
      setIsLoading(false);
    };
    loadUser();
  }, [isAuthenticated]);

  const handleLogin = (userData: User) => {
    setUser(userData);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setIsAuthenticated(false);
    setUser(null);
    setExpenseMode(null);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-slate-900">
        <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return (
      <AuthPage 
        mode={authMode} 
        setMode={setAuthMode} 
        onLogin={(u) => handleLogin(u as User)} 
      />
    );
  }

  if (!expenseMode) {
    return (
      <SelectionScreen 
        userName={user?.name || ''}
        onSelect={(mode) => setExpenseMode(mode)} 
        isDarkMode={isDarkMode}
      />
    );
  }

  const renderView = () => {
    switch (currentView) {
      case AppView.DASHBOARD: return <Dashboard user={user} mode={expenseMode} isDarkMode={isDarkMode} onNavigate={setCurrentView} />;
      case AppView.EXPENSES:
      case AppView.EMPLOYEE_EXPENSES:
        return <ExpenseManager mode={expenseMode} onNavigate={setCurrentView} />;
      case AppView.BUDGETS: return <BudgetTracker />;
      case AppView.SAVINGS_GOALS: return <SavingsGoals />;
      case AppView.CATEGORIES: return <Categories onNavigate={setCurrentView} />;
      case AppView.SUBSCRIPTIONS: return <Subscriptions />;
      case AppView.REPORTS: return <Reports />;
      case AppView.APPROVALS: return <Approvals />;
      case AppView.REIMBURSEMENTS: return <Reimbursements />;
      case AppView.AI_INSIGHTS: return <AiInsights />;
      case AppView.SETTINGS: return user ? <Settings user={user} /> : null;
      default: return <Dashboard user={user} mode={expenseMode} isDarkMode={isDarkMode} onNavigate={setCurrentView} />;
    }
  };

  return (
    <Layout 
      currentView={currentView} 
      setCurrentView={setCurrentView} 
      user={user}
      expenseMode={expenseMode}
      onLogout={handleLogout}
      onChangeMode={() => setExpenseMode(null)}
      isDarkMode={isDarkMode}
      toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
    >
      {renderView()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend 
} from 'recharts';
import { 
  DollarSign, CreditCard, Zap, Briefcase, User as UserIcon, Plus, LayoutList, PieChart as PieIcon, Trash2, Edit3
} from 'lucide-react';
import { apiService } from '../services/api';
import { ExpenseMode, AppView, User, Expense } from '../types';
import { COLORS } from '../constants';

interface DashboardProps {
  user: User | null;
  mode: ExpenseMode;
  isDarkMode: boolean;
  onNavigate: (view: AppView) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, mode, isDarkMode, onNavigate }) => {
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDeleting, setIsDeleting] = useState<string | null>(null);

  const isCompany = mode === ExpenseMode.COMPANY;
  const themeTextClass = isCompany ? 'text-indigo-600' : 'text-emerald-600';
  const themeBgClass = isCompany ? 'bg-indigo-50 dark:bg-indigo-900/20' : 'bg-emerald-50 dark:bg-emerald-900/20';
  const themeBorderClass = isCompany ? 'border-indigo-100 dark:border-indigo-800' : 'border-emerald-100 dark:border-emerald-800';

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const data = await apiService.get('/expenses');
      setExpenses(data);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm('Delete this transaction permanently?')) return;
    setIsDeleting(id);
    try {
      await apiService.delete(`/expenses/${id}`);
      setExpenses(prev => prev.filter(e => String(e.id) !== String(id)));
    } catch (err) {
      alert('Failed to delete transaction');
    } finally {
      setIsDeleting(null);
    }
  };

  const totalSpent = expenses.reduce((sum, e) => sum + e.amount, 0);
  const recentExpenses = expenses.slice(0, 5);

  const categoryDataMap = expenses.reduce((acc, curr) => {
    acc[curr.category] = (acc[curr.category] || 0) + curr.amount;
    return acc;
  }, {} as Record<string, number>);

  const categoryChartData = Object.entries(categoryDataMap).map(([name, value]) => ({
    name,
    value
  })).sort((a, b) => b.value - a.value);

  const getTimeGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return 'Good morning';
    if (hour < 18) return 'Good afternoon';
    return 'Good evening';
  };

  const stats = [
    { 
      label: 'Total Outflow', 
      value: `₹${totalSpent.toLocaleString('en-IN')}`, 
      trend: expenses.length > 0 ? '+0%' : 'No data', 
      isUp: true, 
      icon: DollarSign, 
      bg: isCompany ? 'bg-indigo-50' : 'bg-emerald-50',
      text: isCompany ? 'text-indigo-600' : 'text-emerald-600'
    },
    { 
      label: 'Monthly Goal', 
      value: '₹0', 
      trend: 'Not set', 
      isUp: false, 
      icon: CreditCard, 
      bg: 'bg-blue-50',
      text: 'text-blue-600'
    },
    { 
      label: 'Transactions', 
      value: expenses.length.toString(), 
      trend: 'All time', 
      isUp: true, 
      icon: LayoutList, 
      bg: 'bg-amber-50',
      text: 'text-amber-600'
    },
    { 
      label: 'Budget Usage', 
      value: '0%', 
      trend: 'Healthy', 
      isUp: true, 
      icon: Zap, 
      bg: 'bg-emerald-50',
      text: 'text-emerald-600'
    },
  ];

  return (
    <div className="space-y-6 sm:space-y-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="space-y-1">
          <h1 className="text-3xl sm:text-4xl font-black tracking-tighter">
            {getTimeGreeting()}, {user?.name.split(' ')[0] || 'User'} 👋
          </h1>
          <p className="text-slate-500 text-sm max-w-lg leading-relaxed font-medium">
            {isCompany 
              ? "Here's the latest overview of your company's fiscal activity." 
              : "Let's keep your personal finances on track today."}
          </p>
        </div>
        <div className={`inline-flex items-center self-start gap-2 px-5 py-2.5 ${themeBgClass} border ${themeBorderClass} rounded-2xl`}>
          {isCompany ? <Briefcase size={18} className={themeTextClass} /> : <UserIcon size={18} className={themeTextClass} />}
          <span className={`text-xs font-black uppercase tracking-widest ${themeTextClass}`}>
            {isCompany ? 'Admin View' : 'Personal Workspace'}
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4 sm:gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white dark:bg-slate-800 p-6 rounded-[2.5rem] shadow-sm border border-gray-100 dark:border-slate-700 flex flex-col gap-6 hover:shadow-xl transition-all group">
            <div className="flex items-center justify-between">
              <div className={`p-4 rounded-2xl ${stat.bg} ${stat.text} group-hover:scale-110 transition-transform`}>
                <stat.icon size={28} />
              </div>
              <div className={`flex items-center px-3 py-1 rounded-full text-xs font-black bg-gray-50 text-slate-500`}>
                {stat.trend}
              </div>
            </div>
            <div>
              <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{stat.label}</p>
              <h3 className="text-3xl font-black mt-1 tabular-nums">{stat.value}</h3>
            </div>
          </div>
        ))}
      </div>

      {expenses.length === 0 ? (
        <div className="bg-white dark:bg-slate-800 p-16 rounded-[3rem] border-2 border-dashed border-gray-200 dark:border-slate-700 text-center space-y-6">
          <div className="w-20 h-20 bg-gray-50 dark:bg-slate-900 rounded-full flex items-center justify-center mx-auto">
            <LayoutList size={40} className="text-slate-300" />
          </div>
          <div>
            <h3 className="text-xl font-black">No transactions recorded yet</h3>
            <p className="text-slate-500 max-w-sm mx-auto mt-2">Start by adding your first expense to see your financial analytics here.</p>
          </div>
          <button 
            onClick={() => onNavigate(AppView.EXPENSES)}
            className={`px-8 py-3 ${isCompany ? 'bg-indigo-600' : 'bg-emerald-600'} text-white rounded-2xl font-black flex items-center gap-2 mx-auto hover:scale-105 transition-all shadow-lg`}
          >
            <Plus size={20} />
            Add Your First Expense
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
          <div className="lg:col-span-4 bg-white dark:bg-slate-800 rounded-[3rem] shadow-sm border border-gray-100 dark:border-slate-700 overflow-hidden h-full flex flex-col">
            <div className="p-6 sm:p-8 border-b border-gray-100 dark:border-slate-700 flex items-center gap-3">
              <PieIcon size={20} className={themeTextClass} />
              <h3 className="font-black text-lg">Spending Breakdown</h3>
            </div>
            <div className="flex-1 p-8 min-h-[350px]">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={categoryChartData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={100}
                    paddingAngle={8}
                    dataKey="value"
                    animationBegin={200}
                    animationDuration={1200}
                  >
                    {categoryChartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="none" />
                    ))}
                  </Pie>
                  <Tooltip 
                    contentStyle={{ 
                      borderRadius: '16px', 
                      border: 'none', 
                      boxShadow: '0 10px 25px -5px rgba(0,0,0,0.1)',
                      fontWeight: 'bold',
                      fontSize: '12px'
                    }}
                    formatter={(value: number) => [`₹${value.toLocaleString('en-IN')}`, 'Spent']}
                  />
                  <Legend 
                    verticalAlign="bottom" 
                    iconType="circle" 
                    wrapperStyle={{ paddingTop: '20px', fontSize: '10px', fontWeight: '900', textTransform: 'uppercase', letterSpacing: '0.05em' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="lg:col-span-8 bg-white dark:bg-slate-800 rounded-[3rem] shadow-sm border border-gray-100 dark:border-slate-700 overflow-hidden h-full">
            <div className="p-6 sm:p-8 border-b border-gray-100 dark:border-slate-700 flex items-center justify-between">
              <h3 className="font-black text-lg">Recent Transactions</h3>
              <button 
                onClick={() => onNavigate(isCompany ? AppView.EMPLOYEE_EXPENSES : AppView.EXPENSES)}
                className={`${themeTextClass} text-xs font-black uppercase tracking-widest hover:underline transition-all`}
              >
                View All
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-gray-50/50 dark:bg-slate-900/50">
                    <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Date</th>
                    <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Merchant</th>
                    <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Category</th>
                    <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Amount</th>
                    <th className="px-8 py-5"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50 dark:divide-slate-700/50">
                  {recentExpenses.map((expense) => (
                    <tr key={expense.id} className={`hover:bg-gray-50/50 dark:hover:bg-slate-700/30 transition-colors group ${isDeleting === expense.id ? 'opacity-30' : ''}`}>
                      <td className="px-8 py-6 text-sm font-bold text-slate-400">{new Date(expense.date).toLocaleDateString()}</td>
                      <td className="px-8 py-6 font-black">{expense.merchant}</td>
                      <td className="px-8 py-6">
                        <span className="px-3 py-1 bg-gray-100 dark:bg-slate-700 text-slate-500 rounded-lg text-[10px] font-black uppercase tracking-widest">
                          {expense.category}
                        </span>
                      </td>
                      <td className="px-8 py-6 text-sm font-black tabular-nums">₹{expense.amount.toLocaleString('en-IN')}</td>
                      <td className="px-8 py-6 text-right">
                        <div className="flex items-center justify-end gap-2">
                           <button 
                            onClick={() => onNavigate(AppView.EXPENSES)} // Direct to manager for editing
                            className="p-2 text-slate-300 hover:text-indigo-600 transition-colors"
                          >
                            <Edit3 size={16} />
                          </button>
                          <button 
                            onClick={() => handleDelete(expense.id)}
                            disabled={isDeleting === expense.id}
                            className="p-2 text-slate-300 hover:text-rose-600 transition-colors"
                          >
                            <Trash2 size={16} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Plus, Filter, Search, Download, Trash2, Edit3, MoreVertical, X, Upload, Receipt, Check, FileText, Grid, Wallet, CreditCard, Banknote } from 'lucide-react';
import { apiService } from '../services/api';
import { Expense, ExpenseMode, AppView } from '../types';

interface ExpenseManagerProps {
  mode: ExpenseMode;
  onNavigate?: (view: AppView) => void;
}

const ExpenseManager: React.FC<ExpenseManagerProps> = ({ mode, onNavigate }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [showFilters, setShowFilters] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [userCategories, setUserCategories] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDeleting, setIsDeleting] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    amount: '',
    merchant: '',
    category: '',
    paymentMethod: 'UPI',
    notes: ''
  });

  useEffect(() => {
    fetchExpenses();
    fetchUserCategories();
  }, []);

  const fetchExpenses = async () => {
    setIsLoading(true);
    try {
      const data = await apiService.get('/expenses');
      setExpenses(data);
    } catch (err) {
      console.error('Failed to fetch expenses', err);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchUserCategories = async () => {
    try {
      const cats = await apiService.get('/categories');
      setUserCategories(cats);
      if (cats.length > 0 && !formData.category) {
        setFormData(prev => ({ ...prev, category: cats[0].name }));
      }
    } catch (err) {
      console.error('Failed to fetch categories');
    }
  };

  const handleSaveExpense = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.category) {
      alert('Please select a category. If none exist, create one in the Categories tab.');
      return;
    }

    try {
      if (editingExpense) {
        const updated = await apiService.put(`/expenses/${editingExpense.id}`, formData);
        setExpenses(prev => prev.map(exp => exp.id === updated.id ? updated : exp));
      } else {
        const newExpense = await apiService.post('/expenses', formData);
        setExpenses(prev => [newExpense, ...prev]);
      }

      closeModal();
    } catch (err) {
      alert('Error saving expense');
    }
  };

  const handleEditClick = (expense: Expense) => {
    setEditingExpense(expense);
    setFormData({
      date: expense.date,
      amount: expense.amount.toString(),
      merchant: expense.merchant,
      category: expense.category,
      paymentMethod: expense.paymentMethod,
      notes: expense.notes || ''
    });
    setShowAddModal(true);
  };

  const closeModal = () => {
    setShowAddModal(false);
    setEditingExpense(null);
    setFormData({
      date: new Date().toISOString().split('T')[0],
      amount: '',
      merchant: '',
      category: userCategories.length > 0 ? userCategories[0].name : '',
      paymentMethod: 'UPI',
      notes: ''
    });
  };

  const handleDelete = async (id: string) => {
    if (!id) return;
    if (!window.confirm('Are you sure you want to delete this transaction permanently?')) return;

    setIsDeleting(id);
    try {
      await apiService.delete(`/expenses/${id}`);
      // Smoothly filter out from the UI
      setExpenses(prev => prev.filter(e => String(e.id) !== String(id)));
    } catch (err) {
      console.error('Delete error:', err);
      alert('Failed to delete the transaction. Please try again.');
    } finally {
      setIsDeleting(null);
    }
  };

  const isCompany = mode === ExpenseMode.COMPANY;
  const themeBgBtn = isCompany ? 'bg-indigo-600' : 'bg-emerald-600';

  const filteredExpenses = expenses.filter(e => {
    const matchesSearch = e.merchant.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         e.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || e.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="space-y-6 sm:space-y-8">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black tracking-tighter">{isCompany ? 'Company Claims' : 'Personal Expenses'}</h1>
          <p className="text-slate-500 text-sm font-medium mt-1">Efficiently track your ₹ INR spending.</p>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setShowAddModal(true)} className={`px-8 py-3 ${themeBgBtn} text-white rounded-2xl text-sm font-black shadow-lg transition-all active:scale-95`}>
            Add Expense
          </button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-800 p-6 rounded-[2.5rem] border border-gray-100 flex flex-col md:flex-row gap-4 items-center shadow-sm">
        <div className="relative flex-1 w-full">
          <Search size={18} className="absolute left-4 top-3.5 text-slate-400" />
          <input type="text" placeholder="Search expenses..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-12 pr-4 py-3.5 bg-gray-50 dark:bg-slate-900 border rounded-2xl outline-none focus:ring-4 focus:ring-indigo-500/10" />
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          <select 
            value={selectedCategory} 
            onChange={e => setSelectedCategory(e.target.value)}
            className="px-4 py-3.5 bg-gray-50 dark:bg-slate-900 border rounded-2xl text-sm font-bold outline-none grow md:grow-0"
          >
            <option>All Categories</option>
            {userCategories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
          </select>
          <button onClick={() => setShowFilters(!showFilters)} className={`px-6 py-3.5 bg-gray-50 border rounded-2xl text-sm font-black`}>More Filters</button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-800 rounded-[3rem] border border-gray-100 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-gray-50 dark:bg-slate-900">
