        contents: [
          { role: 'user', parts: [{ text: `User Expense History:\n${expenseContext}\n\nUser Message: ${textToSend}` }] }
        ],
        config: {
          systemInstruction: `You are a professional, friendly, and highly organized financial advisor. 
