import React, { useState } from 'react';
import { AuthView, User as UserType } from '../types';
import { Shield, Mail, Lock, User, ArrowRight, Github, Chrome } from 'lucide-react';
import { apiService } from '../services/api';

interface AuthPageProps {
  mode: AuthView;
  setMode: (mode: AuthView) => void;
  onLogin: (user: UserType) => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ mode, setMode, onLogin }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [formData, setFormData] = useState({ name: '', email: '', password: '', confirmPassword: '' });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      if (mode === AuthView.LOGIN) {
        const data = await apiService.post('/auth/login', { email: formData.email, password: formData.password });
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        onLogin(data.user);
      } else if (mode === AuthView.SIGNUP) {
        if (formData.password !== formData.confirmPassword) {
          throw new Error('Passwords do not match. Please try again.');
        }
        await apiService.post('/auth/signup', { name: formData.name, email: formData.email, password: formData.password });
        setMode(AuthView.LOGIN);
        setError('Registration successful! Please login.');
        setLoading(false);
        return;
      }
    } catch (err: any) {
      setError(err.message || 'Authentication failed');
    } finally {
      setLoading(false);
    }
  };

