import { GoogleGenAI, Type } from "@google/genai";
import { Expense, Income } from '../types';

const USERS_KEY = 'ea_mock_users';
const EXPENSES_KEY = 'ea_mock_expenses';
const INCOME_KEY = 'ea_mock_income';
const CATEGORIES_KEY = 'ea_mock_categories';
const INCOME_CATEGORIES_KEY = 'ea_mock_income_categories';
const USER_DATA_KEY = 'user';

const getLocalUsers = () => JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
const getLocalExpenses = () => JSON.parse(localStorage.getItem(EXPENSES_KEY) || '[]');
const getLocalIncome = () => JSON.parse(localStorage.getItem(INCOME_KEY) || '[]');
const getLocalCategories = () => JSON.parse(localStorage.getItem(CATEGORIES_KEY) || '[]');
const getLocalIncomeCategories = () => JSON.parse(localStorage.getItem(INCOME_CATEGORIES_KEY) || '[]');
const getLoggedInUser = () => JSON.parse(localStorage.getItem(USER_DATA_KEY) || 'null');

const DEFAULT_CATEGORIES = [
  { name: 'Food & Dining', iconName: 'Utensils', color: 'emerald', budget: 5000 },
  { name: 'Transport', iconName: 'Car', color: 'blue', budget: 3000 },
  { name: 'Shopping', iconName: 'ShoppingBag', color: 'rose', budget: 10000 },
  { name: 'Bills & Utilities', iconName: 'Zap', color: 'amber', budget: 2000 },
];

const DEFAULT_INCOME_CATEGORIES = [
  { name: 'Salary', iconName: 'Briefcase', color: 'blue' },
  { name: 'Freelance', iconName: 'Smartphone', color: 'emerald' },
  { name: 'Investments', iconName: 'TrendingUp', color: 'indigo' },
  { name: 'Gift', iconName: 'Target', color: 'rose' },
];

export const apiService = {
  async ocrScan(base64Data: string, mimeType: string) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const imagePart = {
      inlineData: {
        data: base64Data,
        mimeType: mimeType,
      },
    };
    const prompt = `Extract receipt details into JSON. 
    Fields: 
    - date (YYYY-MM-DD)
    - amount (number)
    - merchant (string)
    - category (one of: Food & Dining, Transport, Shopping, Bills & Utilities, Software, Entertainment, Medical, Education, Housing, Work, Tech)
    - notes (string summary)`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [imagePart, { text: prompt }] },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING },
              amount: { type: Type.NUMBER },
              merchant: { type: Type.STRING },
              category: { type: Type.STRING },
              notes: { type: Type.STRING }
            },
            required: ["date", "amount", "merchant", "category"]
          }
        }
      });
      return JSON.parse(response.text || '{}');
    } catch (error) {
      console.error('OCR Extraction failed:', error);
      throw new Error('Failed to analyze receipt. Please enter details manually.');
    }
  },

  async post(endpoint: string, data: any) {
    await new Promise(resolve => setTimeout(resolve, 600));
    const currentUser = getLoggedInUser();

    if (endpoint === '/auth/signup') {
      const users = getLocalUsers();
      if (users.find((u: any) => u.email === data.email)) {
        throw new Error('An account with this email already exists.');
      }
      const newUser = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        createdAt: new Date(),
        role: 'Personal User'
      };
      users.push(newUser);
      localStorage.setItem(USERS_KEY, JSON.stringify(users));

      // Seed default categories for new user
      const allCategories = getLocalCategories();
      const userDefaults = DEFAULT_CATEGORIES.map(cat => ({
        ...cat,
        userId: newUser.id,
        id: Math.random().toString(36).substr(2, 9),
      }));
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify([...allCategories, ...userDefaults]));

      // Seed default income categories
      const allIncomeCategories = getLocalIncomeCategories();
      const userIncomeDefaults = DEFAULT_INCOME_CATEGORIES.map(cat => ({
        ...cat,
        userId: newUser.id,
        id: Math.random().toString(36).substr(2, 9),
      }));
      localStorage.setItem(INCOME_CATEGORIES_KEY, JSON.stringify([...allIncomeCategories, ...userIncomeDefaults]));

      return { message: 'Registration successful' };
    }

    if (endpoint === '/auth/login') {
      const users = getLocalUsers();
      const user = users.find((u: any) => u.email === data.email && u.password === data.password);
      if (!user) throw new Error('Invalid email or password credentials.');

      const token = btoa(JSON.stringify({ id: user.id, email: user.email }));
      const userPublic = { name: user.name, email: user.email, id: user.id, role: user.role };
      localStorage.setItem(USER_DATA_KEY, JSON.stringify(userPublic));
      return { token, user: userPublic };
    }

    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      const newExpense = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        userId: currentUser.id,
        amount: parseFloat(data.amount),
        status: 'approved' 
      };
      expenses.push(newExpense);
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(expenses));
      return newExpense;
    }

    if (endpoint === '/income') {
      const incomeList = getLocalIncome();
      const newIncome = { 
        ...data, 
        id: Math.random().toString(36).substr(2, 9), 
        userId: currentUser.id,
        amount: parseFloat(data.amount)
      };
      incomeList.push(newIncome);
      localStorage.setItem(INCOME_KEY, JSON.stringify(incomeList));
      return newIncome;
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const newCategory = {
        ...data,
        userId: currentUser.id,
        id: Math.random().toString(36).substr(2, 9),
      };
      categories.push(newCategory);
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(categories));
      return newCategory;
    }

    if (endpoint === '/income-categories') {
      const categories = getLocalIncomeCategories();
      const newCategory = {
        ...data,
        userId: currentUser.id,
        id: Math.random().toString(36).substr(2, 9),
      };
      categories.push(newCategory);
      localStorage.setItem(INCOME_CATEGORIES_KEY, JSON.stringify(categories));
      return newCategory;
    }

    throw new Error('Endpoint not found');
  },

  async put(endpoint: string, data: any) {
    await new Promise(resolve => setTimeout(resolve, 400));
    const currentUser = getLoggedInUser();
    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint.startsWith('/expenses/')) {
      const id = endpoint.split('/expenses/')[1];
      const expenses = getLocalExpenses();
      const index = expenses.findIndex((e: any) => String(e.id) === String(id) && String(e.userId) === String(currentUser.id));

      if (index === -1) throw new Error('Expense not found');

      const updatedExpense = { ...expenses[index], ...data, amount: parseFloat(data.amount) };
      expenses[index] = updatedExpense;
      localStorage.setItem(EXPENSES_KEY, JSON.stringify(expenses));
      return updatedExpense;
    }

    if (endpoint.startsWith('/income/')) {
      const id = endpoint.split('/income/')[1];
      const incomeList = getLocalIncome();
      const index = incomeList.findIndex((e: any) => String(e.id) === String(id) && String(e.userId) === String(currentUser.id));

      if (index === -1) throw new Error('Income record not found');

      const updatedIncome = { ...incomeList[index], ...data, amount: parseFloat(data.amount) };
      incomeList[index] = updatedIncome;
      localStorage.setItem(INCOME_KEY, JSON.stringify(incomeList));
      return updatedIncome;
    }

    if (endpoint.startsWith('/categories/')) {
      const id = endpoint.split('/categories/')[1];
      const categories = getLocalCategories();
      const index = categories.findIndex((c: any) => String(c.id) === String(id) && String(c.userId) === String(currentUser.id));

      if (index === -1) throw new Error('Category not found');

      const updatedCategory = { ...categories[index], ...data, budget: parseFloat(data.budget) || 0 };
      categories[index] = updatedCategory;
      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(categories));
      return updatedCategory;
    }

    if (endpoint.startsWith('/income-categories/')) {
      const id = endpoint.split('/income-categories/')[1];
      const categories = getLocalIncomeCategories();
      const index = categories.findIndex((c: any) => String(c.id) === String(id) && String(c.userId) === String(currentUser.id));

      if (index === -1) throw new Error('Income category not found');

      const updatedCategory = { ...categories[index], ...data };
      categories[index] = updatedCategory;
      localStorage.setItem(INCOME_CATEGORIES_KEY, JSON.stringify(categories));
      return updatedCategory;
    }

    throw new Error('Endpoint not found');
  },

  async get(endpoint: string) {
    await new Promise(resolve => setTimeout(resolve, 400));
    const currentUser = getLoggedInUser();

    if (endpoint === '/user/me') {
      if (!currentUser) throw new Error('Unauthorized');
      return currentUser;
    }

    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint === '/expenses') {
      const expenses = getLocalExpenses();
      return expenses.filter((e: any) => e.userId === currentUser.id).reverse();
    }

    if (endpoint === '/income') {
      const incomeList = getLocalIncome();
      return incomeList.filter((e: any) => e.userId === currentUser.id).reverse();
    }

    if (endpoint === '/categories') {
      const categories = getLocalCategories();
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);

      let userCategories = categories.filter((c: any) => c.userId === currentUser.id);

      if (userCategories.length === 0) {
        const userDefaults = DEFAULT_CATEGORIES.map(cat => ({
          ...cat,
          userId: currentUser.id,
          id: Math.random().toString(36).substr(2, 9),
        }));
        const allCategories = getLocalCategories();
        localStorage.setItem(CATEGORIES_KEY, JSON.stringify([...allCategories, ...userDefaults]));
        userCategories = userDefaults;
      }

      return userCategories.map((cat: any) => {
        const catExpenses = expenses.filter((e: any) => e.category === cat.name);
        const totalSpent = catExpenses.reduce((sum: number, e: any) => sum + e.amount, 0);
        return {
          ...cat,
          spent: totalSpent,
          count: catExpenses.length
        };
      });
    }

    if (endpoint === '/income-categories') {
      const categories = getLocalIncomeCategories();
      const incomeList = getLocalIncome().filter((e: any) => e.userId === currentUser.id);

      let userCategories = categories.filter((c: any) => c.userId === currentUser.id);

      if (userCategories.length === 0) {
        // Fix: Changed userIncomeDefaults to userDefaults as defined a few lines above.
        const userDefaults = DEFAULT_INCOME_CATEGORIES.map(cat => ({
          ...cat,
          userId: currentUser.id,
          id: Math.random().toString(36).substr(2, 9),
        }));
        const allCategories = getLocalIncomeCategories();
        localStorage.setItem(INCOME_CATEGORIES_KEY, JSON.stringify([...allCategories, ...userDefaults]));
        userCategories = userDefaults;
      }

      return userCategories.map((cat: any) => {
        const catIncome = incomeList.filter((e: any) => e.category === cat.name);
        const totalAmount = catIncome.reduce((sum: number, e: any) => sum + e.amount, 0);
        return {
          ...cat,
          amount: totalAmount,
          count: catIncome.length
        };
      });
    }

    if (endpoint === '/ai/insights') {
      const expenses = getLocalExpenses().filter((e: any) => e.userId === currentUser.id);

      if (expenses.length === 0) {
        return { 
          summary: `Hi ${currentUser.name}, welcome to Expense Analyzer! Start adding your expenses to unlock personalized AI financial insights.`,
          suggestions: ["Add your first expense", "Track your daily commute costs", "Set a grocery budget"]
        };
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const expenseData = expenses.slice(0, 30).map((e: any) => 
          `${e.date}: ₹${e.amount} at ${e.merchant} (${e.category})`
        ).join('\n');

        const response = await ai.models.generateContent({
          model: "gemini-3-flash-preview",
          contents: `User: ${currentUser.name}. Expenses: ${expenseData}. Analyze these expenses in INR. Provide a 1-sentence summary and 3 tips.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                summary: { type: Type.STRING },
                suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["summary", "suggestions"]
            }
          }
        });

        return JSON.parse(response.text || '{}');
      } catch (error) {
        return { summary: "AI insights temporarily unavailable.", suggestions: [] };
      }
    }
    throw new Error('Endpoint not found');
  },

  async delete(endpoint: string) {
    await new Promise(resolve => setTimeout(resolve, 400));

    const currentUser = getLoggedInUser();
    if (!currentUser) throw new Error('Unauthorized');

    if (endpoint.includes('/expenses/')) {
      const id = endpoint.split('/expenses/')[1].split('/')[0];
      const expenses = getLocalExpenses();

      const filtered = expenses.filter((e: any) => {
        const isTarget = String(e.id) === String(id);
        const belongsToUser = String(e.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(EXPENSES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    if (endpoint.includes('/income/')) {
      const id = endpoint.split('/income/')[1].split('/')[0];
      const incomeList = getLocalIncome();

      const filtered = incomeList.filter((e: any) => {
        const isTarget = String(e.id) === String(id);
        const belongsToUser = String(e.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(INCOME_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    if (endpoint.includes('/categories/')) {
      const id = endpoint.split('/categories/')[1].split('/')[0];
      const categories = getLocalCategories();

      const filtered = categories.filter((c: any) => {
        const isTarget = String(c.id) === String(id);
        const belongsToUser = String(c.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(CATEGORIES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    if (endpoint.includes('/income-categories/')) {
      const id = endpoint.split('/income-categories/')[1].split('/')[0];
      const categories = getLocalIncomeCategories();

      const filtered = categories.filter((c: any) => {
        const isTarget = String(c.id) === String(id);
        const belongsToUser = String(c.userId) === String(currentUser.id);
        return !(isTarget && belongsToUser);
      });

      localStorage.setItem(INCOME_CATEGORIES_KEY, JSON.stringify(filtered));
      return { success: true };
    }

    throw new Error(`Endpoint not supported: ${endpoint}`);
  }
};

import React, { useState, useEffect } from 'react';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid
} from 'recharts';
import { 
  DollarSign, CreditCard, Zap, Briefcase, User as UserIcon, Plus, LayoutList, PieChart as PieIcon, Trash2, Edit3, IndianRupee, TrendingUp
} from 'lucide-react';
import { apiService } from '../services/api';
import { ExpenseMode, AppView, User, Expense, Income } from '../types';
import { COLORS } from '../constants';

interface DashboardProps {
  user: User | null;
  mode: ExpenseMode;
  isDarkMode: boolean;
  onNavigate: (view: AppView) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, mode, isDarkMode, onNavigate }) => {
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [incomeList, setIncomeList] = useState<Income[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDeleting, setIsDeleting] = useState<string | null>(null);

  const isCompany = mode === ExpenseMode.COMPANY;
  const themeTextClass = isCompany ? 'text-indigo-600' : 'text-emerald-600';
  const themeBgClass = isCompany ? 'bg-indigo-50 dark:bg-indigo-900/20' : 'bg-emerald-50 dark:bg-emerald-900/20';
  const themeBorderClass = isCompany ? 'border-indigo-100 dark:border-indigo-800' : 'border-emerald-100 dark:border-emerald-800';

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const [expData, incData] = await Promise.all([
        apiService.get('/expenses'),
        apiService.get('/income')
      ]);
      setExpenses(expData);
      setIncomeList(incData);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm('Delete this transaction permanently?')) return;
    setIsDeleting(id);
    try {
      await apiService.delete(`/expenses/${id}`);
      setExpenses(prev => prev.filter(e => String(e.id) !== String(id)));
    } catch (err) {
      alert('Failed to delete transaction');
    } finally {
      setIsDeleting(null);
    }
  };

  const totalSpent = expenses.reduce((sum, e) => sum + e.amount, 0);
  const totalIncome = incomeList.reduce((sum, e) => sum + e.amount, 0);
  const recentExpenses = expenses.slice(0, 5);

  const categoryDataMap = expenses.reduce((acc, curr) => {
    acc[curr.category] = (acc[curr.category] || 0) + curr.amount;
    return acc;
  }, {} as Record<string, number>);

  const categoryChartData = Object.entries(categoryDataMap).map(([name, value]) => ({
    name,
    value
    // Fix: Cast a and b to any to satisfy TS compiler regarding arithmetic operation on unknown types
  })).sort((a: any, b: any) => b.value - a.value);

  // Prepare data for Income vs Expense Bar Chart
  const last6Months = Array.from({ length: 6 }, (_, i) => {
    const d = new Date();
    // Fix: Explicitly treat i as number for arithmetic operation
    d.setMonth(d.getMonth() - (5 - (i as number)));
    return {
      month: d.toLocaleString('default', { month: 'short' }),
      monthIndex: d.getMonth(),
      year: d.getFullYear()
    };
  });

  const comparisonData = last6Months.map(m => {
    const monthExp = expenses
      .filter(e => {
        const d = new Date(e.date);
        return d.getMonth() === m.monthIndex && d.getFullYear() === m.year;
      })
      .reduce((sum, e) => sum + e.amount, 0);

    const monthInc = incomeList
      .filter(e => {
        const d = new Date(e.date);
        return d.getMonth() === m.monthIndex && d.getFullYear() === m.year;
      })
      .reduce((sum, e) => sum + e.amount, 0);

    return {
      name: m.month,
      Income: monthInc,
      Expense: monthExp
    };
  });

  const getTimeGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return 'Good morning';
    if (hour < 18) return 'Good afternoon';
    return 'Good evening';
  };

  const stats = [
    { 
      label: 'Total Income', 
      value: `₹${totalIncome.toLocaleString('en-IN')}`, 
      trend: 'Lifetime', 
      isUp: true, 
      icon: IndianRupee, 
      bg: 'bg-emerald-50',
      text: 'text-emerald-600'
    },
    { 
      label: 'Total Expenses', 
      value: `₹${totalSpent.toLocaleString('en-IN')}`, 
      trend: 'Lifetime', 
      isUp: false, 
      icon: DollarSign, 
      bg: isCompany ? 'bg-indigo-50' : 'bg-rose-50',
      text: isCompany ? 'text-indigo-600' : 'text-rose-600'
    },
    { 
      label: 'Net Balance', 
      // Fix: Cast operands to number to prevent arithmetic type errors on potential any/unknown types
      value: `₹${(Number(totalIncome) - Number(totalSpent)).toLocaleString('en-IN')}`, 
      trend: 'Current', 
      // Fix: Cast operands to number to prevent arithmetic type errors on potential any/unknown types
      isUp: (Number(totalIncome) - Number(totalSpent)) >= 0, 
      icon: TrendingUp, 
      bg: 'bg-blue-50',
      text: 'text-blue-600'
    },
    { 
      label: 'Transactions', 
      value: (expenses.length + incomeList.length).toString(), 
      trend: 'All time', 
      isUp: true, 
      icon: LayoutList, 
      bg: 'bg-amber-50',
      text: 'text-amber-600'
    },
  ];

  return (
    <div className="space-y-6 sm:space-y-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="space-y-1">
          <h1 className="text-3xl sm:text-4xl font-black tracking-tighter">
            {getTimeGreeting()}, {user?.name.split(' ')[0] || 'User'} 👋
          </h1>
          <p className="text-slate-500 text-sm max-w-lg leading-relaxed font-medium">
            {isCompany 
              ? "Here's the latest overview of your company's fiscal activity." 
              : "Keep your balance healthy and your expenses tracked."}
          </p>
        </div>
        <div className={`inline-flex items-center self-start gap-2 px-5 py-2.5 ${themeBgClass} border ${themeBorderClass} rounded-2xl`}>
          {isCompany ? <Briefcase size={18} className={themeTextClass} /> : <UserIcon size={18} className={themeTextClass} />}
          <span className={`text-xs font-black uppercase tracking-widest ${themeTextClass}`}>
            {isCompany ? 'Admin View' : 'Personal Workspace'}
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4 sm:gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white dark:bg-slate-800 p-6 rounded-[2.5rem] shadow-sm border border-gray-100 dark:border-slate-700 flex flex-col gap-6 hover:shadow-xl transition-all group">
            <div className="flex items-center justify-between">
              <div className={`p-4 rounded-2xl ${stat.bg} ${stat.text} group-hover:scale-110 transition-transform`}>
                <stat.icon size={28} />
              </div>
              <div className={`flex items-center px-3 py-1 rounded-full text-xs font-black bg-gray-50 text-slate-500`}>
                {stat.trend}
              </div>
            </div>
            <div>
              <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{stat.label}</p>
              <h3 className="text-3xl font-black mt-1 tabular-nums">{stat.value}</h3>
            </div>
          </div>
        ))}
      </div>

      {!isLoading && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
          <div className="lg:col-span-8 bg-white dark:bg-slate-800 rounded-[3rem] shadow-sm border border-gray-100 dark:border-slate-700 overflow-hidden h-full flex flex-col">
            <div className="p-6 sm:p-8 border-b border-gray-100 dark:border-slate-700 flex items-center justify-between">
               <div className="flex items-center gap-3">
                  <TrendingUp size={20} className="text-emerald-600" />
                  <h3 className="font-black text-lg">Cash Flow Analysis</h3>
               </div>
            </div>
            <div className="flex-1 p-8 min-h-[350px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={comparisonData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#f1f5f9'} />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 12, fontWeight: 700 }} />
                  <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 700 }} />
                  <Tooltip 
                    cursor={{ fill: 'transparent' }}
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px -5px rgba(0,0,0,0.1)', fontWeight: 'bold' }}
                  />
                  <Legend verticalAlign="top" align="right" wrapperStyle={{ paddingBottom: '20px', fontSize: '12px', fontWeight: 'bold' }} />
                  <Bar dataKey="Income" fill="#10b981" radius={[10, 10, 0, 0]} barSize={30} />
                  <Bar dataKey="Expense" fill="#f43f5e" radius={[10, 10, 0, 0]} barSize={30} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="lg:col-span-4 bg-white dark:bg-slate-800 rounded-[3rem] shadow-sm border border-gray-100 dark:border-slate-700 overflow-hidden h-full flex flex-col">
            <div className="p-6 sm:p-8 border-b border-gray-100 dark:border-slate-700 flex items-center gap-3">
              <PieIcon size={20} className={themeTextClass} />
              <h3 className="font-black text-lg">Expense Breakdown</h3>
            </div>
            <div className="flex-1 p-8 min-h-[350px]">
              {expenses.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-400 italic">
                  No expense data available
                </div>
              ) : (
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={categoryChartData}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={100}
                      paddingAngle={8}
                      dataKey="value"
                    >
                      {categoryChartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="none" />
                      ))}
                    </Pie>
                    <Tooltip contentStyle={{ borderRadius: '12px', fontWeight: 'bold' }} />
                    <Legend verticalAlign="bottom" wrapperStyle={{ fontSize: '10px', fontWeight: 900 }} />
                  </PieChart>
                </ResponsiveContainer>
              )}
            </div>
          </div>
        </div>
      )}

      {expenses.length > 0 && (
        <div className="bg-white dark:bg-slate-800 rounded-[3rem] shadow-sm border border-gray-100 dark:border-slate-700 overflow-hidden">
          <div className="p-6 sm:p-8 border-b border-gray-100 dark:border-slate-700 flex items-center justify-between">
            <h3 className="font-black text-lg">Recent Transactions</h3>
            <button 
              onClick={() => onNavigate(AppView.EXPENSES)}
              className={`${themeTextClass} text-xs font-black uppercase tracking-widest hover:underline transition-all`}
            >
              View All
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-gray-50/50 dark:bg-slate-900/50">
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Date</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Merchant/Source</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Category</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Amount</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50 dark:divide-slate-700/50">
                {recentExpenses.map((expense) => (
                  <tr key={expense.id} className="hover:bg-gray-50 dark:hover:bg-slate-700/30 transition-colors">
                    <td className="px-8 py-6 text-sm font-bold text-slate-400">{new Date(expense.date).toLocaleDateString()}</td>
                    <td className="px-8 py-6 font-black">{expense.merchant}</td>
                    <td className="px-8 py-6">
                      <span className="px-3 py-1 bg-gray-100 dark:bg-slate-700 text-slate-500 rounded-lg text-[10px] font-black uppercase tracking-widest">
                        {expense.category}
                      </span>
                    </td>
                    <td className="px-8 py-6 text-sm font-black tabular-nums text-rose-500">- ₹{expense.amount.toLocaleString('en-IN')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Building2, User as UserIcon, ChevronRight, Sparkles, Plus, Users, ArrowLeft, LogIn, Search, ShieldCheck, Settings, Mail, Lock, FileText, CheckCircle2 } from 'lucide-react';
import { ExpenseMode } from '../types';

interface SelectionScreenProps {
  userName: string;
  onSelect: (mode: ExpenseMode) => void;
  isDarkMode: boolean;
}

interface Team {
  id: string;
  name: string;
  role: string;
  members: number;
  avatar: string;
  description?: string;
}

const TEAMS_STORAGE_KEY = 'ea_user_joined_teams';

const SelectionScreen: React.FC<SelectionScreenProps> = ({ userName, onSelect, isDarkMode }) => {
  const [view, setView] = useState<'workspace' | 'teams'>('workspace');
  const [teamFormView, setTeamFormView] = useState<'actions' | 'create'>('actions');
  const [joinedTeams, setJoinedTeams] = useState<Team[]>([]);

  // Create Team Form State
  const [createFormData, setCreateFormData] = useState({
    orgName: '',
    adminEmail: '',
    description: '',
    password: '',
    confirmPassword: ''
  });
  const [formError, setFormError] = useState('');

  // Load teams from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem(TEAMS_STORAGE_KEY);
    if (saved) {
      try {
        setJoinedTeams(JSON.parse(saved));
      } catch (e) {
        setJoinedTeams([]);
      }
    }
  }, []);

  const handleCreateTeam = (e: React.FormEvent) => {
    e.preventDefault();
    setFormError('');

    if (createFormData.password !== createFormData.confirmPassword) {
      setFormError('Passwords do not match');
      return;
    }

    if (createFormData.password.length < 8) {
      setFormError('Password must be at least 8 characters');
      return;
    }

    const newTeam: Team = {
      id: Math.random().toString(36).substr(2, 9),
      name: createFormData.orgName,
      role: 'Admin',
      members: 1,
      avatar: createFormData.orgName.substring(0, 2).toUpperCase(),
      description: createFormData.description
    };

    const updatedTeams = [...joinedTeams, newTeam];
    setJoinedTeams(updatedTeams);
    localStorage.setItem(TEAMS_STORAGE_KEY, JSON.stringify(updatedTeams));

    // Reset form and return to actions view
    setCreateFormData({
      orgName: '',
      adminEmail: '',
      description: '',
      password: '',
      confirmPassword: ''
    });
    setTeamFormView('actions');
  };

  if (view === 'teams') {
    return (
      <div className={`min-h-screen flex items-center justify-center p-4 sm:p-6 lg:p-10 ${isDarkMode ? 'bg-slate-900 text-slate-100' : 'bg-gray-50 text-slate-900'}`}>
        <div className="max-w-6xl w-full bg-white dark:bg-slate-800 rounded-[3rem] shadow-2xl overflow-hidden flex flex-col lg:flex-row border border-gray-100 dark:border-slate-700 min-h-[750px] animate-in slide-in-from-bottom-8 duration-500">

          {/* Left Side: Team Login / Joined Teams */}
          <div className={`lg:w-1/3 p-8 lg:p-12 border-b lg:border-b-0 lg:border-r ${isDarkMode ? 'bg-slate-800/50 border-slate-700' : 'bg-gray-50/50 border-gray-100'}`}>
            <button 
              onClick={() => setView('workspace')}
              className="flex items-center gap-2 text-slate-400 hover:text-indigo-600 font-bold text-xs uppercase tracking-widest mb-10 transition-colors"
            >
              <ArrowLeft size={16} /> Back to Workspaces
            </button>

            <div className="space-y-2 mb-8">
              <h2 className="text-2xl font-black tracking-tight">Your Teams</h2>
              <p className="text-slate-500 text-sm font-medium">Select a team to access your corporate dashboard.</p>
            </div>

            <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
              {joinedTeams.length === 0 ? (
                <div className="p-8 border-2 border-dashed border-gray-200 dark:border-slate-700 rounded-3xl flex flex-col items-center justify-center text-center space-y-4 opacity-60">
                  <div className="p-4 bg-gray-100 dark:bg-slate-800 rounded-full text-slate-400">
                    <Users size={24} />
                  </div>
                  <div>
                    <p className="text-xs font-black uppercase tracking-widest text-slate-500">No Teams Joined</p>
                    <p className="text-[10px] text-slate-400 mt-1 font-medium">Create a new team or join an existing one to get started.</p>
                  </div>
                </div>
              ) : (
                joinedTeams.map((team) => (
                  <button 
                    key={team.id}
                    onClick={() => onSelect(ExpenseMode.COMPANY)}
                    className="w-full flex items-center gap-4 p-5 bg-white dark:bg-slate-900 rounded-[2rem] border border-gray-100 dark:border-slate-700 hover:border-indigo-500 hover:shadow-xl hover:-translate-y-1 transition-all group text-left"
                  >
                    <div className="w-12 h-12 bg-indigo-600 text-white rounded-2xl flex items-center justify-center font-black text-sm shrink-0 group-hover:rotate-6 transition-transform">
                      {team.avatar}
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="font-bold text-sm truncate">{team.name}</p>
                      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest truncate">{team.role} • {team.members} Member{team.members > 1 ? 's' : ''}</p>
                    </div>
                    <LogIn size={18} className="text-slate-300 group-hover:text-indigo-600 group-hover:translate-x-1 transition-all" />
                  </button>
                ))
              )}
            </div>
          </div>

          {/* Right Side: Actions or Create Form */}
          <div className="flex-1 p-8 lg:p-20 flex flex-col justify-center items-center">
            {teamFormView === 'actions' ? (
              <div className="w-full text-center space-y-12 animate-in fade-in duration-500">
                <div className="max-w-md mx-auto space-y-4">
                  <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 text-xs font-black uppercase tracking-widest">
                    <ShieldCheck size={14} /> Organization Management
                  </div>
                  <h1 className="text-4xl font-black tracking-tighter leading-tight">Empower your organization.</h1>
                  <p className="text-slate-500 font-medium">Streamline expense workflows by creating a dedicated organizational workspace.</p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full max-w-2xl">
                  {/* Create Team Card */}
                  <button 
                    onClick={() => setTeamFormView('create')}
                    className="group p-10 bg-indigo-600 text-white rounded-[3rem] shadow-2xl shadow-indigo-100 dark:shadow-none hover:-translate-y-2 transition-all flex flex-col items-center text-center"
                  >
                    <div className="w-20 h-20 bg-white/20 rounded-3xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
                      <Plus size={40} />
                    </div>
                    <h3 className="text-2xl font-black mb-2">Create a Team</h3>
                    <p className="text-indigo-100 text-sm font-medium leading-relaxed">
                      Establish a central hub for your company's finances.
                    </p>
                  </button>

                  {/* Join Team Card */}
                  <button 
                    onClick={() => onSelect(ExpenseMode.COMPANY)}
                    className="group p-10 bg-white dark:bg-slate-900 rounded-[3rem] border border-gray-100 dark:border-slate-700 hover:border-indigo-500 hover:shadow-2xl hover:-translate-y-2 transition-all flex flex-col items-center text-center"
                  >
                    <div className="w-20 h-20 bg-gray-100 dark:bg-slate-800 text-indigo-600 rounded-3xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
                      <Users size={40} />
                    </div>
                    <h3 className="text-2xl font-black mb-2 text-slate-900 dark:text-white">Join a Team</h3>
                    <p className="text-slate-500 text-sm font-medium leading-relaxed">
                      Connect with your existing team via invite code.
                    </p>
                  </button>
                </div>

                <div className="flex items-center gap-8 pt-8 opacity-40">
                  <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest"><Settings size={14} /> SSO Support</div>
                  <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest"><Building2 size={14} /> Multi-Entity</div>
                </div>
              </div>
            ) : (
              <div className="w-full max-w-xl animate-in slide-in-from-right-8 duration-500">
                <button 
