interface DashboardProps {
  user: User | null;
  mode: ExpenseMode;
  isDarkMode: boolean;
  onNavigate: (view: AppView) => void;
}

type TimeFrame = 'today' | 'month' | 'year' | 'lifetime';

const Dashboard: React.FC<DashboardProps> = ({ user, mode, isDarkMode, onNavigate }) => {
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [incomeList, setIncomeList] = useState<Income[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // State for per-card filters
  const [incomeFilter, setIncomeFilter] = useState<TimeFrame>('lifetime');
  const [expenseFilter, setExpenseFilter] = useState<TimeFrame>('lifetime');
  const [balanceFilter, setBalanceFilter] = useState<TimeFrame>('lifetime');
  const [transactionsFilter, setTransactionsFilter] = useState<TimeFrame>('lifetime');

  // Dropdown open states
  const [openDropdown, setOpenDropdown] = useState<string | null>(null);

  const isCompany = mode === ExpenseMode.COMPANY;
  const themeTextClass = isCompany ? 'text-indigo-600' : 'text-emerald-600';
  const themeBgClass = isCompany ? 'bg-indigo-50 dark:bg-indigo-900/20' : 'bg-emerald-50 dark:bg-emerald-900/20';
  const themeBorderClass = isCompany ? 'border-indigo-100 dark:border-indigo-800' : 'border-emerald-100 dark:border-emerald-800';

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const [expData, incData] = await Promise.all([
        apiService.get('/expenses'),
        apiService.get('/income')
      ]);
      setExpenses(expData);
      setIncomeList(incData);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const filterDataByTime = (data: any[], timeframe: TimeFrame) => {
    const now = new Date();
    const today = now.toISOString().split('T')[0];
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();

    return data.filter(item => {
      const itemDate = new Date(item.date);
      if (timeframe === 'today') {
        return item.date.startsWith(today);
      }
      if (timeframe === 'month') {
        return itemDate.getMonth() === currentMonth && itemDate.getFullYear() === currentYear;
      }
      if (timeframe === 'year') {
        return itemDate.getFullYear() === currentYear;
      }
      return true; // lifetime
    });
  };

  const filteredIncome = useMemo(() => filterDataByTime(incomeList, incomeFilter), [incomeList, incomeFilter]);
  const filteredExpenses = useMemo(() => filterDataByTime(expenses, expenseFilter), [expenses, expenseFilter]);

  // Balance needs both but according to a single filter
  const balanceIncome = useMemo(() => filterDataByTime(incomeList, balanceFilter), [incomeList, balanceFilter]);
  const balanceExpenses = useMemo(() => filterDataByTime(expenses, balanceFilter), [expenses, balanceFilter]);

  // Transactions total count
  const countIncome = useMemo(() => filterDataByTime(incomeList, transactionsFilter), [incomeList, transactionsFilter]);
  const countExpenses = useMemo(() => filterDataByTime(expenses, transactionsFilter), [expenses, transactionsFilter]);

  const totalIncomeVal = filteredIncome.reduce((sum, e) => sum + e.amount, 0);
  const totalSpentVal = filteredExpenses.reduce((sum, e) => sum + e.amount, 0);
  const totalBalanceVal = balanceIncome.reduce((sum, e) => sum + e.amount, 0) - balanceExpenses.reduce((sum, e) => sum + e.amount, 0);
  const totalTransactionsCount = countIncome.length + countExpenses.length;

  const getTimeFrameLabel = (tf: TimeFrame) => {
    switch(tf) {
      case 'today': return 'Today';
      case 'month': return 'This Month';
      case 'year': return 'This Year';
      default: return 'Lifetime';
    }
  };

  const stats = [
    { 
      id: 'income',
      label: 'Total Income', 
      value: `₹${totalIncomeVal.toLocaleString('en-IN')}`, 
      timeframe: incomeFilter,
      setTimeframe: setIncomeFilter,
      icon: IndianRupee, 
      bg: 'bg-emerald-50',
      text: 'text-emerald-600'
    },
    { 
      id: 'expense',
      label: 'Total Expenses', 
      value: `₹${totalSpentVal.toLocaleString('en-IN')}`, 
