      text: isCompany ? 'text-indigo-600' : 'text-rose-600'
    },
    { 
      id: 'balance',
      label: 'Net Balance', 
      value: `₹${totalBalanceVal.toLocaleString('en-IN')}`, 
      timeframe: balanceFilter,
      setTimeframe: setBalanceFilter,
      icon: TrendingUp, 
      bg: 'bg-blue-50',
      text: 'text-blue-600'
